const PWD_SALT="ctbz$2026#hub";
// Hash de senha · síncrono, determinístico, NÃO reversível (suficiente para storage local).
function hashPwd(pwd){const s=PWD_SALT+(pwd==null?"":String(pwd));let h1=0x811c9dc5,h2=0x1505;for(let i=0;i<s.length;i++){const c=s.charCodeAt(i);h1=Math.imul(h1^c,0x01000193)>>>0;h2=((h2<<5)+h2+c)>>>0;}return "h2$"+h1.toString(36)+h2.toString(36)+"$"+s.length.toString(36);}
const isHashed=(p)=>typeof p==="string"&&p.indexOf("h2$")===0;
// Compatível com senhas-semente em texto puro (ex.: "123") e com as novas em hash.
const pwdMatches=(stored,plain)=>{if(stored==null)return false;return isHashed(stored)?stored===hashPwd(plain):String(stored)===String(plain);};
const genTempPwd=()=>{const a="ABCDEFGHJKLMNPQRSTUVWXYZ23456789";let o="";for(let i=0;i<8;i++)o+=a[Math.floor(Math.random()*a.length)];return o;};
// Validadores de formato (feedback inline; não bloqueiam, apenas avisam)
function onlyDigits(s){return (s||"").replace(/\D/g,"");}
function validCPF(s){const c=onlyDigits(s);if(c.length!==11||/^(\d)\1{10}$/.test(c))return false;let r;let sum=0;for(let i=0;i<9;i++)sum+=+c[i]*(10-i);r=(sum*10)%11;if(r===10)r=0;if(r!==+c[9])return false;sum=0;for(let i=0;i<10;i++)sum+=+c[i]*(11-i);r=(sum*10)%11;if(r===10)r=0;return r===+c[10];}
function validCNPJ(s){const c=onlyDigits(s);if(c.length!==14||/^(\d)\1{13}$/.test(c))return false;const calc=(len)=>{let sum=0,pos=len-7;for(let i=len;i>=1;i--){sum+=+c[len-i]*pos--;if(pos<2)pos=9;}const r=sum%11;return r<2?0:11-r;};return calc(12)===+c[12]&&calc(13)===+c[13];}

