function tempoCasa(adm){if(!adm)return "–";const a=new Date(adm+"T00:00:00"),n=new Date();if(isNaN(a))return "–";let y=n.getFullYear()-a.getFullYear(),m=n.getMonth()-a.getMonth(),d=n.getDate()-a.getDate();if(d<0){m--;d+=new Date(n.getFullYear(),n.getMonth(),0).getDate();}if(m<0){y--;m+=12;}return `${y}a ${m}m ${d}d`;}
