// Indicador REAL do mês: derivado de colaboradores (admissão/demissão) e ausências.
function realIndicador(rh,ym){
  const cps=(rh&&rh.colaboradores)||[];
  const endStr=ym+"-31",prevEnd=ymFromCiG(ci(ym)-1)+"-31";
  const activeAt=(d)=>cps.filter(c=>{const a=c.adm||"";if(!a||a>d)return false;const dm=c.demissao||"";return !dm||dm>d;}).length;
  const hf=activeAt(endStr),hi=activeAt(prevEnd);
  const adm=cps.filter(c=>(c.adm||"").slice(0,7)===ym).length;
  const dem=cps.filter(c=>(c.demissao||"").slice(0,7)===ym).length;
  const horasFalta=((rh&&rh.ausencias)||[]).filter(a=>a.mesRef===ym&&!a.abona).reduce((s,a)=>s+(+a.horas||0),0);
  const faltas=Math.round(horasFalta/8.8*10)/10;
  const manual=((rh&&rh.indicadores)||[]).find(r=>r.mes===ym)||{};
  return {mes:ym,hi,hf,adm,dem,faltas,acuidade:(manual.acuidade!=null&&manual.acuidade!==""?manual.acuidade:"")};
}
