const DEPTS=[{key:"central",label:"Cadastro Central",icon:Building2,hint:"Fonte única"},{key:"fiscal",label:"Fiscal",icon:Receipt},{key:"pessoal",label:"Pessoal",icon:Users},{key:"contabil",label:"Contábil",icon:BookOpen},{key:"paralegal",label:"Paralegal",icon:Scale},{key:"financeiro",label:"Financeiro",icon:Wallet},{key:"recepcao",label:"Recepção",icon:Phone},{key:"rh",label:"RH Interno",icon:UserCog},{key:"estoque",label:"Controle de Estoque",icon:Package},{key:"certificados",label:"Certificados Digitais",icon:ShieldCheck},{key:"motoboy",label:"Motoboy",icon:MotorcycleIcon}];
