const FISCAL_FORM=[{sec:"Observações importantes",rows:[{k:"fat",l:"Faturamento Mensal",t:"money"},{k:"distLucro",l:"Distribuição de Lucro",t:"text"},{k:"fatorR",l:"Fator R",t:"sel",o:SN},{k:"concomitante",l:"Concomitante",t:"sel",o:SN},{k:"obrigTEF",l:"Obrigat. TEF",t:"sel",o:SN},{k:"stAntecip",l:"Recolh. ST Antecip.",t:"sel",o:SN},{k:"beneficioFiscal",l:"Benefício Fiscal",t:"text"}]},
{sec:"Escrituração",rows:[{k:"entradas",l:"Entradas",t:"money"},{k:"saidas",l:"Saídas",t:"money"},{k:"servPrest",l:"Serv. Prestados",t:"money"},{k:"servTom",l:"Serv. Tomados",t:"money"},{k:"cteEmit",l:"CT-e Emit.",t:"money"},{k:"cteTom",l:"CT-e Tom.",t:"money"},{k:"nfce",l:"NFC-e",t:"money"}]},
{sec:"Impostos",rows:[{k:"pis",l:"PIS",t:"money"},{k:"cofins",l:"COFINS",t:"money"},{k:"csll",l:"CSLL",t:"money"},{k:"irpj",l:"IRPJ",t:"money"},{k:"issqn",l:"ISSQN",t:"money"},{k:"simples",l:"Simples N.",t:"money"},{k:"icms",l:"ICMS Mensal",t:"money"},{k:"icmsDifal",l:"ICMS Difal",t:"money"}]},
{sec:"Retenções",rows:[{k:"irrf",l:"IRRF",t:"money"},{k:"crf",l:"CRF",t:"money"},{k:"inssRet",l:"INSS Ret.",t:"money"},{k:"senar",l:"SENAR",t:"money"},{k:"funrural",l:"FUNRURAL",t:"money"},{k:"fethab",l:"FETHAB",t:"money"},{k:"iagro",l:"IAGRO",t:"money"}]},
{sec:"Encerramento fiscal",rows:[{k:"fiscalConcluido",l:"Concluído",t:"sel",o:SN},{k:"fiscalDataConcl",l:"Data de conclusão",t:"date"},{k:"formaEnvio",l:"Forma de envio",t:"text"},{k:"dataEnvio",l:"Data de envio",t:"date"},{k:"fiscalConfirmacao",l:"Confirmação",t:"sel",o:SN},{k:"pdfCreditos",l:"PDF - Créditos",t:"text"}]}];
const PESSOAL_FORM=[{sec:"Folha",rows:[{k:"tipoFolha",l:"Tipo de Folha",t:"sel",o:["LANÇAMENTO","FOLHA","PRÓ-LABORE","PROLABORE","SEM FOLHA","INATIVA"]},{k:"distLucroPess",l:"Dist. Lucro",t:"text"},{k:"sindicatos",l:"Sindicatos",t:"text"},{k:"dissidio",l:"Dissídio",t:"text"},{k:"obsFolha",l:"Observações p/ Folha",t:"text"}]},
{sec:"Processamento",rows:[{k:"holerites",l:"Holerites",t:"status"},{k:"vrCesta",l:"VR/Cesta/Gás",t:"status"},{k:"alocRPA",l:"Aloc. RPA",t:"status"},{k:"fgts",l:"FGTS",t:"status"},{k:"darfDae",l:"DARF/DAE",t:"status"},{k:"dcomp",l:"DCOMP",t:"status"},{k:"retificacao",l:"Retificação",t:"sel",o:SN}]},
{sec:"Encerramento",rows:[{k:"pessoalConcluido",l:"Concluído",t:"sel",o:SN},{k:"pessoalData",l:"Data",t:"date"},{k:"confEnvio",l:"Confirmação de Envio",t:"sel",o:SN},{k:"modalidade",l:"Modalidade de Envio",t:"text"},{k:"protocolo",l:"N° Protocolo/E-mail",t:"text"}]}];
const STAT_OPTS=["Pendente","Em andamento","Concluído"];
const deptEmps=(emps,d)=>emps.filter(e=>e.ativo&&e.dept===d).map(e=>e.nome);
const FLABEL={}; FISCAL_FORM.forEach(s=>s.rows.forEach(r=>FLABEL[r.k]=r.l));
const PLABEL={}; PESSOAL_FORM.forEach(s=>s.rows.forEach(r=>PLABEL[r.k]=r.l));
const CLABEL={codigo:"Código",razao:"Razão social",cnpj:"CNPJ",regime:"Regime",municipio:"Município",situacao:"Situação",dataSituacao:"Data situação"};
function disp(v){return (v===""||v===undefined||v===null)?"–":String(v);}
function diffPD(o,n,kind){const ch=[]; if((o.semMovimento||false)!==(n.semMovimento||false))ch.push("Sem movimento: "+(o.semMovimento?"Sim":"Não")+" → "+(n.semMovimento?"Sim":"Não"));
  if(kind==="fiscal"){const a=o.fiscal,b=n.fiscal; Object.keys(FLABEL).forEach(k=>{if((a[k]??"")!==(b[k]??""))ch.push(FLABEL[k]+": "+disp(a[k])+" → "+disp(b[k]));}); OBRIG.forEach(([l,k])=>{if(a.obrig[k].obrig!==b.obrig[k].obrig)ch.push(l+": "+a.obrig[k].obrig+" → "+b.obrig[k].obrig); if((a.obrig[k].data||"")!==(b.obrig[k].data||""))ch.push(l+" (data): "+disp(a.obrig[k].data)+" → "+disp(b.obrig[k].data));}); [["coordFiscal","Coord. Fiscal"],["depContabil","Dep. Contábil"]].forEach(([g,lab])=>{if(a[g].fin!==b[g].fin)ch.push(lab+": "+a[g].fin+" → "+b[g].fin);});}
  else{const a=o.pessoal,b=n.pessoal; Object.keys(PLABEL).forEach(k=>{if((a[k]??"")!==(b[k]??""))ch.push(PLABEL[k]+": "+disp(a[k])+" → "+disp(b[k]));});}
  return ch; }

export default function App(){
  const [me,setMe]=useState(null);
  const [db,setDb]=useState(null);
  const [loading,setLoading]=useState(true);
  const [comp,setComp]=useState(CUR_YM<START_YM?START_YM:CUR_YM);
  const [active,setActive]=useState("dashboard");
  const [query,setQuery]=useState("");
  const [f,setF]=useState({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"});
  const [sort,setSort]=useState({key:"razao",dir:1});
  const [view,setView]=useState("lista");
  const [editId,setEditId]=useState(null);const [draft,setDraft]=useState({});
  const [delId,setDelId]=useState(null);const [adding,setAdding]=useState(false);const [cadEdit,setCadEdit]=useState(null);const [openId,setOpenId]=useState(null);
  const [empEdit,setEmpEdit]=useState(null);
  const [sessChecked,setSessChecked]=useState(false);
  const [showProfile,setShowProfile]=useState(false);
  const [toast,setToast]=useState(null);
  const notify=(m,kind)=>{setToast({m,kind});setTimeout(()=>setToast(null),2600);};
  const [theme,setTheme]=useState("system");
  const [sysDark,setSysDark]=useState(false);
  const [mobileNav,setMobileNav]=useState(false);
  const [sidebarCollapsed,setSidebarCollapsed]=useState(false);
  useEffect(()=>{setMobileNav(false);},[active]);
  useEffect(()=>{if(typeof window==="undefined"||!window.matchMedia)return;const mq=window.matchMedia("(prefers-color-scheme: dark)");setSysDark(mq.matches);const h=e=>setSysDark(e.matches);try{mq.addEventListener("change",h);}catch(e){mq.addListener(h);}return ()=>{try{mq.removeEventListener("change",h);}catch(e){mq.removeListener(h);}};},[]);
  useEffect(()=>{if(typeof window!=="undefined"&&window.storage){window.storage.get("contabilizar:theme",false).then(r=>{if(r&&r.value)setTheme(r.value);}).catch(()=>{});}},[]);
  const setThemeP=(v)=>{setTheme(v);if(typeof window!=="undefined"&&window.storage){window.storage.set("contabilizar:theme",v,false).catch(()=>{});}};
  const themeR=theme==="system"?(sysDark?"dark":"light"):theme;

  useEffect(()=>{let alive=true;(async()=>{
    const seed={registry:REGISTRY_SEED,employees:EMP_SEED,periods:{},log:[],rh:RH_SEED,areas:[],labels:{},regimes:REGIME_SEED,hiddenDepts:[]};
    if(typeof window==="undefined"||!window.storage){ if(alive){setDb(seed);setLoading(false);} return; }
    try{const r=await window.storage.get(DB_KEY,true); if(alive&&r&&r.value){setDb(JSON.parse(r.value));setLoading(false);return;}}catch(e){}
    if(alive){setDb(seed);setLoading(false); try{await window.storage.set(DB_KEY,JSON.stringify(seed),true);}catch(e){}}
  })();return ()=>{alive=false;};},[]);

  // Sincronização periódica em segundo plano (polling) a cada 15 segundos para múltiplas máquinas
  useEffect(() => {
    let alive = true;
    const interval = setInterval(async () => {
      try {
        if (typeof window !== "undefined" && window.storage) {
          const r = await window.storage.get(DB_KEY, true);
          if (alive && r && r.value) {
            const fetched = JSON.parse(r.value);
            setDb(prev => {
              if (prev && JSON.stringify(prev) !== r.value) {
                return fetched;
              }
              return prev;
            });
          }
        }
      } catch (e) {
        console.error("Erro no polling de sincronização:", e);
      }
    }, 15000);
    return () => {
      alive = false;
      clearInterval(interval);
    };
  }, []);

  const mutate=(fn,logAction)=>{ setDb(prev=>{ let next=fn(prev); if(logAction){next={...next,log:[...(prev.log||[]),{ts:Date.now(),user:me?me.nome:"–",action:logAction}].slice(-1000)};} if(typeof window!=="undefined"&&window.storage){window.storage.set(DB_KEY,JSON.stringify(next),true).catch(()=>{});} return next; }); };

  // Sessão persistente com expiração (TTL). Restaura o login após recarregar, respeitando 8h.
  const saveSession=(u)=>{if(typeof window!=="undefined"&&window.storage&&u)window.storage.set(SESS_KEY,JSON.stringify({id:u.id,ts:Date.now()}),false).catch(()=>{});};
  const login=(u)=>{setMe(u);setActive("dashboard");saveSession(u);};
  const logout=()=>{setMe(null);setActive("dashboard");if(typeof window!=="undefined"&&window.storage)window.storage.delete(SESS_KEY,false).catch(()=>{});};
  useEffect(()=>{ if(!db){return;} if(me){setSessChecked(true);return;} let alive=true; (async()=>{
    try{ if(typeof window!=="undefined"&&window.storage){ const r=await window.storage.get(SESS_KEY,false); if(r&&r.value){ const s=JSON.parse(r.value); if(s&&s.id&&(Date.now()-s.ts)<SESS_TTL){ const u=(db.employees||[]).find(x=>x.id===s.id&&x.ativo); if(u&&alive){setMe(u);} else {window.storage.delete(SESS_KEY,false).catch(()=>{});} } else { window.storage.delete(SESS_KEY,false).catch(()=>{}); } } } }catch(e){}
    if(alive)setSessChecked(true);
  })(); return ()=>{alive=false;}; },[db]);
  // Conclui a troca obrigatória de senha (1º acesso) e atualiza a sessão atual.
  const completeForcePwd=(newPlain)=>{const h=hashPwd(newPlain);mutate(prev=>({...prev,employees:prev.employees.map(x=>x.id===me.id?{...x,pwd:h,mustChangePwd:false}:x)}),`Segurança · ${me.nome} alterou a própria senha (troca obrigatória)`);setMe(m=>({...m,pwd:h,mustChangePwd:false}));notify("Senha atualizada com sucesso.","ok");};
  // Auto-edição de perfil (não altera permissões).
  const saveProfile=(patch)=>{mutate(prev=>({...prev,employees:prev.employees.map(x=>x.id===me.id?{...x,...patch}:x)}),`Perfil · ${me.nome} atualizou os próprios dados`);setMe(m=>({...m,...patch}));setShowProfile(false);notify("Perfil atualizado.","ok");};

  const registry=db?db.registry:[];
  const employees=db?db.employees:EMP_SEED;
  const periods=db?db.periods:{};
  const rh=db&&db.rh?db.rh:RH_SEED;
  const areas=db&&db.areas?db.areas:[];
  const labels=db&&db.labels?db.labels:{};
  const saveRh=(fn,log)=>mutate(prev=>({...prev,rh:fn(prev.rh||RH_SEED)}),log);
  const saveMotoboy=(fn,log)=>mutate(prev=>({...prev,motoboy:fn(prev.motoboy||{solicitacoes:[],veiculo:[],abastecimento:[],oleo:[],manutencao:[]})}),log);
  const saveAreas=(fn,log)=>mutate(prev=>({...prev,areas:fn(prev.areas||[])}),log);
  const saveLabels=(fn,log)=>mutate(prev=>({...prev,labels:fn(prev.labels||{})}),log);
  const regimes=db&&db.regimes?db.regimes:REGIME_SEED;
  const startYm=(db&&db.startYm)||START_YM;
  const prazos=db&&db.prazos?db.prazos:{};
  const savePrazos=(fn,log)=>mutate(prev=>({...prev,prazos:fn(prev.prazos||{})}),log);
  const comps=useMemo(()=>buildCompsFrom(startYm),[startYm]);
  const setStartYm=(v)=>mutate(prev=>({...prev,startYm:v}),"Configuração · competência inicial: "+compLabel(v));
  useEffect(()=>{if(comps.length&&!comps.includes(comp))setComp(comps[comps.length-1]);},[comps]);
  const hiddenDepts=db&&db.hiddenDepts?db.hiddenDepts:[];
  const saveRegimes=(fn,log)=>mutate(prev=>({...prev,regimes:fn(prev.regimes||REGIME_SEED)}),log);
  const saveHidden=(fn)=>mutate(prev=>({...prev,hiddenDepts:fn(prev.hiddenDepts||[])}));

  const isAdmin=me&&!!me.isAdmin;
  const canManageCentral=me&&(isAdmin||!!me.canCentral);
  const canEditDept=(d)=>me&&(isAdmin||d==="estoque"||d==="certificados"||d==="motoboy"||me.deptEdit===d);
  const canView=(d)=>me&&(isAdmin||d==="estoque"||d==="certificados"||(d==="motoboy"&&(me.view.includes("motoboy_solic")||me.view.includes("motoboy_manut")))||(me.view||[]).includes(d));
  const canAssignHere=(kind)=>me&&(isAdmin||(me.canAssign&&me.deptEdit===kind));
  const canEditFicha=(c,kind)=>{ if(!me)return false; if(isAdmin)return true; if(me.deptEdit!==kind)return false; if(me.onlyAssigned){const r=kind==="fiscal"?c.respFiscal:c.respPessoal; return r===me.nome;} return true; };

  const getPD=(c)=>mergePD(periods[comp]&&periods[comp][c.id],c);
  const updateReg=(id,patch,log)=>mutate(prev=>({...prev,registry:prev.registry.map(c=>c.id===id?{...c,...patch}:c)}),log);
  const editCell=(c,kind,mutator)=>{const old=mergePD(periods[comp]&&periods[comp][c.id],c);const nx=mutator(JSON.parse(JSON.stringify(old)));nx._meta={by:me.nome,at:Date.now()};const ch=diffPD(old,nx,kind);const logStr=ch.length?`${kind==="fiscal"?"Fiscal":"Pessoal"} · ${c.razao} (${compLabel(comp)}): ${ch.join("; ")}`:null;mutate(prev=>({...prev,periods:{...prev.periods,[comp]:{...(prev.periods[comp]||{}),[c.id]:nx}}}),logStr);};

  const municipios=useMemo(()=>[...new Set(registry.map(c=>c.municipio).filter(Boolean))].sort(),[registry]);
  const inComp=useMemo(()=>registry.filter(c=>isActiveIn(c,comp)),[registry,comp]);
  const respField=active==="fiscal"?"respFiscal":active==="pessoal"?"respPessoal":null;
  const respOpts=active==="fiscal"?deptEmps(employees,"fiscal"):active==="pessoal"?deptEmps(employees,"pessoal"):null;

  const applyFilters=(list)=>{const q=query.trim().toLowerCase();return list.filter(c=>{
    if(q&&!((c.razao||"").toLowerCase().includes(q)||(c.cnpj||"").includes(q)||String(c.codigo).includes(q)))return false;
    if(f.regime!=="todos"&&c.regime!==f.regime)return false;
    if(f.municipio!=="todos"&&c.municipio!==f.municipio)return false;
    if(f.situacao!=="todos"&&c.situacao!==f.situacao)return false;
    if(respField&&f.resp!=="todos"&&c[respField]!==f.resp)return false;
    return true;});};
  const centralList=useMemo(()=>sortBy(applyFilters(registry),sort),[registry,query,f,sort]);
  const deptList=useMemo(()=>sortBy(applyFilters(inComp),sort),[inComp,query,f,active,sort]);

  const statsOf=(kind,list)=>{let sum=0,c100=0,pend=0,applic=0,na=0;const tot=list.length;const applicSet=new Set();list.forEach(c=>{const pd=getPD(c);const ex=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);if(ex){na++;return;}applic++;if(kind==="fiscal"){const rOs=(regimes||[]).find(r=>r.nome===c.regime)||null;OBRIG.forEach(([,k])=>{if(!rOs||!rOs.fiscal||rOs.fiscal[k]!=="nao_obrigada")applicSet.add(k);});}const v=kind==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c);sum+=v;if(v===100)c100++;else pend++;});
    const obrig={};if(kind==="fiscal"){OBRIG.forEach(([,k])=>{let a=0,d=0;list.forEach(c=>{const pd=getPD(c);if(pd.semMovimento)return;const _rO=(regimes||[]).find(r=>r.nome===c.regime)||null;if(_rO&&_rO.fiscal&&_rO.fiscal[k]==="nao_obrigada")return;const val=pd.fiscal.obrig?.[k]?.obrig||"";if(val==="Pendente"||val==="Entregue"){a++;if(val==="Entregue")d++;}});obrig[k]=a?Math.round(d/a*100):0;});}
    return {avg:applic?Math.round(sum/applic):0,c100,pend,na,applic,tot,obrig,applicableObrig:[...applicSet]};};
  const modStats=useMemo(()=>active==="fiscal"||active==="pessoal"?statsOf(active,deptList):null,[active,deptList,periods,comp]);

  if(loading||!db||!sessChecked) return <Splash />;
  if(!me) return <Login employees={employees} onLogin={login} themeR={themeR} theme={theme} setTheme={setThemeP} />;
  if(me.mustChangePwd) return <ForcePwd me={me} themeR={themeR} onDone={completeForcePwd} onLogout={logout} />;
  const opened=registry.find(c=>c.id===openId);
  const navDepts=DEPTS.filter(d=>canView(d.key)&&!hiddenDepts.includes(d.key));
  const pendForDept=(d)=>(d!=="fiscal"&&d!=="pessoal")?0:inComp.filter(c=>{const pd=getPD(c);return !(d==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c))&&(d==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c))<100;}).length;
  const pendCount=me?['fiscal','pessoal'].filter(d=>canView(d)).reduce((sum,d)=>sum+pendForDept(d),0):0;
  const allowed=new Set(["dashboard",...navDepts.map(d=>d.key),...areas.map(a=>"area:"+a.key)]); if(isAdmin){allowed.add("equipe");allowed.add("historico");allowed.add("config");allowed.add("depts");allowed.add("regimes");}
  const act=allowed.has(active)?active:"dashboard";
  const meLabel=isAdmin?"Administrador":(me.cargo||"Colaborador");
  const showComp=!["equipe","historico","rh","config","depts","regimes","estoque","certificados"].includes(act)&&!act.startsWith("area:");
  const showFilters=["central","fiscal","pessoal"].includes(act);
  const areaActive=act.startsWith("area:")?areas.find(a=>("area:"+a.key)===act):null; const title={dashboard:"Início",equipe:"Equipe & Acessos",historico:"Histórico de alterações",config:"Config. Gerais",depts:"Gestão de Departamentos",regimes:"Regimes & Obrigações"}[act]||(areaActive?areaActive.label:(labels[act]||DEPT_LABEL[act]));

  const saveFicha=(regPatch,newPD)=>{ const id=opened.id; const razao=opened.razao; const oldPD=mergePD(periods[comp]&&periods[comp][id],opened);
    const ch=diffPD(oldPD,newPD,act); if(regPatch.respFiscal!==undefined)ch.push("Resp. Fiscal → "+(regPatch.respFiscal||"–")); if(regPatch.respPessoal!==undefined)ch.push("Resp. Pessoal → "+(regPatch.respPessoal||"–"));
    const logStr=ch.length?`${act==="fiscal"?"Fiscal":"Pessoal"} · ${razao} (${compLabel(comp)}): ${ch.join("; ")}`:null;
    mutate(prev=>{const reg=Object.keys(regPatch).length?prev.registry.map(c=>c.id===id?{...c,...regPatch}:c):prev.registry; const periods={...prev.periods,[comp]:{...(prev.periods[comp]||{}),[id]:{...newPD,_meta:{ts:Date.now()}}}}; return {...prev,registry:reg,periods};}, logStr);
    notify("Ficha salva.","ok"); setOpenId(null); };
  const batchAssignResp=(ids,resp,kind)=>{mutate(prev=>({...prev,registry:prev.registry.map(c=>ids.has(c.id)?{...c,...(kind==="fiscal"?{respFiscal:resp}:{respPessoal:resp})}:c)}));notify(`Responsável atribuído a ${ids.size} empresa${ids.size!==1?"s":""}.`,"ok");};
  const addNote=(id,text)=>{const t=(text||"").trim();if(!t)return;const razao=(registry.find(c=>c.id===id)||{}).razao||("#"+id);mutate(prev=>({...prev,notes:{...(prev.notes||{}),[id]:[...((prev.notes||{})[id]||[]),{ts:Date.now(),by:me.nome,text:t}]}}),"Nota · "+razao);notify("Nota adicionada.","ok");};
  const notesFor=(id)=>(db&&db.notes&&db.notes[id])||[];
  const exportConsolidado=()=>{const rows=inComp.map(c=>{const pd=getPD(c);const fEx=fiscalExcl(pd);const pEx=pessoalExcl(pd,c);return [c.codigo,c.razao,c.cnpj,c.regime,c.municipio,c.respFiscal||"–",fEx?fEx:fiscalNum(pd,c,regimes)+"%",c.respPessoal||"–",pEx?pEx:pessoalNum(pd,c)+"%",c.situacao];});downloadCSV("relatorio_consolidado_"+comp,["Cód","Razão social","CNPJ","Regime","Município","Resp. Fiscal","Progresso Fiscal","Resp. Pessoal","Progresso Pessoal","Situação"],rows);notify("Relatório consolidado gerado.","ok");};
  const notif=(()=>{const items=[];const tasks=[];['fiscal','pessoal'].forEach(d=>{if(!(isAdmin||me.deptEdit===d))return;inComp.forEach(c=>{const resp=d==='fiscal'?c.respFiscal:c.respPessoal;if(resp!==me.nome)return;const pd=getPD(c);const ex=d==='fiscal'?fiscalExcl(pd):pessoalExcl(pd,c);if(ex)return;const v=d==='fiscal'?fiscalNum(pd,c,regimes):pessoalNum(pd,c);if(v<100)tasks.push({d,c,v});});});
    tasks.slice(0,15).forEach(t=>items.push({icon:ClipboardList,color:C.amber,title:t.c.razao,sub:`${t.d==='fiscal'?'Fiscal':'Pessoal'} pendente · ${t.v}%`,onClick:()=>{setActive(t.d);setView("lista");setOpenId(t.c.id);}}));
    let deadlineFlag=false;let nd=null;tasks.forEach(t=>{if(t.d==='fiscal'){const x=fiscalNextDue(t.c,getPD(t.c),comp,regimes,prazos);if(x&&(!nd||x.date<nd.date))nd=x;}});
    if(nd){const today=new Date();today.setHours(0,0,0,0);const dl=Math.round((nd.date-today)/86400000);if(nd.overdue){deadlineFlag=true;items.unshift({icon:AlertCircle,color:C.red,title:"Obrigação(ões) em atraso",sub:`A partir de ${fmtDM(nd.date)} · ${compLabel(comp)}`});}else if(dl<=7){deadlineFlag=true;items.unshift({icon:Clock,color:C.amber,title:`Próx. vencimento em ${dl} dia(s)`,sub:`${fmtDM(nd.date)} · ${compLabel(comp)}`});}}
    ((db&&db.log)?db.log:[]).slice(-8).reverse().filter(e=>e.user&&e.user!==me.nome).slice(0,4).forEach(e=>items.push({icon:History,color:C.muted,title:e.user,sub:e.action,muted:true}));
    let rhCount=0;
    if(isAdmin||me.deptEdit==="rh"||canView("rh")){const ra=rhAlerts(rh);rhCount=ra.filter(a=>a.prio>=2).length;ra.slice(0,10).forEach(a=>{const Ic=a.icon||Dot;items.unshift({icon:Ic,color:a.color,title:a.title,sub:"RH · "+a.sub,onClick:()=>{setActive("rh");}});});}
    return {count:tasks.length+(deadlineFlag?1:0)+rhCount,items};
  })();

  return (
    <div data-theme={themeR} style={{position:"relative",display:"flex",height:"100vh",minHeight:600,background:C.bg,color:C.ink,overflow:"hidden"}}>
      <style>{FONTS}</style>
      <aside className={"sidebar"+(mobileNav?" open":"")} style={{width:sidebarCollapsed?64:248,background:C.card,borderRight:`1px solid ${C.line}`,display:"flex",flexDirection:"column",flexShrink:0,transition:"width .22s cubic-bezier(.4,0,.2,1)",overflow:"visible",position:"relative"}}>
        <div style={{padding:"16px 18px 12px",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",flexShrink:0,minHeight:58,overflow:"hidden"}}>
          {sidebarCollapsed?<img src={LOGO_SYM} alt="C" style={{height:28,display:"block",margin:"0 auto"}} />:<><img src={LOGO_WORD} alt="CONTABILIZARe" className="logo" style={{height:22,display:"block"}} /><div style={{fontSize:10.5,color:window.location.hostname==="localhost"?C.amber:C.muted,letterSpacing:1.8,marginTop:4,whiteSpace:"nowrap",marginLeft:8}}>{window.location.hostname==="localhost"?"🧪 HOMOLOGAÇÃO":"HUB INTERNO"}</div></>}
        </div>
        <button onClick={()=>setSidebarCollapsed(v=>!v)} title={sidebarCollapsed?"Expandir menu":"Recolher menu"} style={{position:"absolute",top:16,right:-13,zIndex:50,width:26,height:26,borderRadius:"50%",border:`1.5px solid ${C.line}`,background:C.card,color:C.muted,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 1px 4px rgba(0,0,0,.10)"}}>{sidebarCollapsed?<ChevronRight size={13}/>:<ArrowLeft size={13}/>}</button>
        <nav style={{flex:1,padding:"8px 10px",overflow:"auto"}}>
          <NavItem collapsed={sidebarCollapsed} icon={Home} label="Início" on={act==="dashboard"} onClick={()=>setActive("dashboard")} badge={pendCount}/>
          {!sidebarCollapsed&&<div style={{padding:"6px 12px 4px",fontSize:10.5,fontWeight:800,color:C.muted,letterSpacing:1.2,textTransform:"uppercase"}}>Operacional</div>}
          <div style={{height:1,background:C.line,margin:"4px 6px 6px"}} />
          {navDepts.map(d=>{const home=me.deptEdit===d.key;return <NavItem collapsed={sidebarCollapsed} key={d.key} icon={d.icon} label={labels[d.key]||d.label} hint={d.hint} dot={home&&!d.hint} on={act===d.key} badge={pendForDept(d.key)} onClick={()=>{setActive(d.key);setEditId(null);setDelId(null);setF({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"});}} />;})}
          {areas.length>0&&<div style={{height:1,background:C.line,margin:"8px 6px"}} />}
          {areas.filter(ar=>!hiddenDepts.includes(ar.key)).map(ar=><NavItem collapsed={sidebarCollapsed} key={ar.key} icon={Layers} label={ar.label} on={act==="area:"+ar.key} onClick={()=>setActive("area:"+ar.key)} />)}
          {isAdmin&&<><div style={{height:1,background:C.line,margin:"8px 6px"}} />
          {!sidebarCollapsed&&<div style={{padding:"6px 12px 4px",fontSize:10.5,fontWeight:800,color:C.muted,letterSpacing:1.2,textTransform:"uppercase"}}>Administração</div>}
          <NavItem collapsed={sidebarCollapsed} icon={UserPlus} label="Equipe & Acessos" on={act==="equipe"} onClick={()=>setActive("equipe")} />
          <NavItem collapsed={sidebarCollapsed} icon={History} label="Histórico" on={act==="historico"} onClick={()=>setActive("historico")} />
          <NavItem collapsed={sidebarCollapsed} icon={Building2} label="Departamentos" on={act==="depts"} onClick={()=>setActive("depts")} />
          <NavItem collapsed={sidebarCollapsed} icon={Scale} label="Regimes & Obrigações" on={act==="regimes"} onClick={()=>setActive("regimes")} />
          <NavItem collapsed={sidebarCollapsed} icon={Settings} label="Config. Gerais" on={act==="config"} onClick={()=>setActive("config")} /></>}
        </nav>
        {<div style={{padding:"8px 12px",borderTop:`1px solid ${C.line}`,display:"flex",gap:6,justifyContent:sidebarCollapsed?"center":"flex-start"}}>{sidebarCollapsed?[["light",Sun],["dark",Moon],["system",Monitor]].filter(([k])=>theme===k).map(([k,Ic])=><button key={k} onClick={()=>setSidebarCollapsed(false)} title="Expandir para mudar tema" style={{display:"flex",alignItems:"center",justifyContent:"center",padding:"7px 6px",borderRadius:8,border:`1px solid ${C.navy}`,background:C.navySoft,color:C.navy,cursor:"pointer"}}><Ic size={15}/></button>):[["light",Sun],["dark",Moon],["system",Monitor]].map(([k,Ic])=>{const on=theme===k;return <button key={k} onClick={()=>setThemeP(k)} title={k==="light"?"Claro":k==="dark"?"Escuro":"Sistema"} style={{flex:1,display:"flex",alignItems:"center",justifyContent:"center",padding:"7px 6px",borderRadius:8,border:`1px solid ${on?C.navy:C.line}`,background:on?C.navySoft:"transparent",color:on?C.navy:C.muted,cursor:"pointer"}}><Ic size={15}/></button>;})}</div>}
        <div style={{padding:12,borderTop:`1px solid ${C.line}`,display:"flex",alignItems:"center",gap:sidebarCollapsed?0:10,justifyContent:sidebarCollapsed?"center":"flex-start"}}>
          <button onClick={()=>setShowProfile(true)} title="Meu perfil" style={{background:"none",border:"none",cursor:"pointer",padding:0,flexShrink:0}}><Avatar nome={me.nome} src={me.avatar} size={32} /></button>
          {!sidebarCollapsed&&<button onClick={()=>setShowProfile(true)} title="Meu perfil" style={{flex:1,minWidth:0,textAlign:"left",background:"none",border:"none",cursor:"pointer",padding:0}}><div style={{fontSize:14,fontWeight:700,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis",color:C.ink}}>{me.nome}</div><div style={{color:C.muted,fontSize:12.5}}>{meLabel}</div></button>}
          {!sidebarCollapsed&&<button onClick={()=>setShowProfile(true)} title="Meu perfil" style={{background:"none",border:"none",color:C.muted,cursor:"pointer"}}><UserCircle size={17} /></button>}
          {!sidebarCollapsed&&<button onClick={logout} title="Sair" style={{background:"none",border:"none",color:C.muted,cursor:"pointer"}}><LogOut size={16} /></button>}
        </div>
      </aside>

      {mobileNav&&<div onClick={()=>setMobileNav(false)} className="sidebar-backdrop" style={{position:"fixed",inset:0,background:"rgba(12,22,64,.4)",zIndex:45}} />}
      <main style={{flex:1,display:"flex",flexDirection:"column",minWidth:0}}>
        <header className="appheader" style={{display:"flex",alignItems:"center",gap:10,flexWrap:"wrap",padding:"14px 24px",borderBottom:`1px solid ${C.line}`,background:C.card,flexShrink:0}}>
          <button className="hamb" onClick={()=>setMobileNav(v=>!v)} style={{alignItems:"center",justifyContent:"center",width:40,height:40,borderRadius:9,border:`1px solid ${C.line}`,background:C.card,color:C.ink,cursor:"pointer",flexShrink:0}}><Menu size={19}/></button><div style={{flex:1,minWidth:0}}><div style={{fontSize:12.5,color:C.muted,letterSpacing:1.2,textTransform:"uppercase",fontWeight:600}}>{meLabel}</div>
            <h1 style={{margin:"2px 0 0",fontSize:23.5,fontWeight:800,color:C.ink,letterSpacing:-0.3}}>{title}</h1></div>
          {showComp&&<div style={{display:"flex",alignItems:"center",gap:7,padding:"8px 14px",borderRadius:10,background:C.navySoft,border:`2px solid ${C.navy}`,boxShadow:"0 0 0 3px rgba(22,34,74,.07)"}}><Calendar size={15} color={C.navy} /><select value={comp} onChange={e=>setComp(e.target.value)} style={{border:"none",background:"transparent",fontSize:15.5,fontWeight:800,color:C.navy,cursor:"pointer",letterSpacing:-.3}}>{comps.slice().reverse().map(c=><option key={c} value={c}>{compLabel(c)}</option>)}</select></div>}
          {(act==="fiscal"||act==="pessoal")&&<div style={{display:"flex",borderRadius:9,border:`1px solid ${C.line}`,overflow:"hidden"}}>{[["lista","Lista"],["planilha","Planilha"]].map(([k,l])=><button key={k} onClick={()=>setView(k)} style={{padding:"8px 13px",border:"none",background:view===k?C.navy:C.card,color:view===k?"#fff":C.body,fontSize:14,fontWeight:700,cursor:"pointer"}}>{l}</button>)}</div>}
          {act==="central"&&<button onClick={()=>canManageCentral?setAdding(true):notify("Apenas Admin e Financeiro incluem empresas.","deny")} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 13px",borderRadius:9,cursor:"pointer",fontSize:14.5,fontWeight:700,background:canManageCentral?C.navy:C.bg,color:canManageCentral?"#fff":C.muted,border:canManageCentral?"none":`1px solid ${C.line}`}}>{canManageCentral?<Plus size={16} />:<Lock size={14} />} Nova empresa</button>}
          {act==="equipe"&&<button onClick={()=>setEmpEdit({})} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 13px",borderRadius:9,cursor:"pointer",fontSize:14.5,fontWeight:700,background:C.navy,color:"#fff",border:"none"}}><UserPlus size={16} /> Novo funcionário</button>}
          {act==="dashboard"&&<button onClick={exportConsolidado} title="Exportar relatório consolidado do mês" style={ghostBtn}><Download size={14}/> Relatório do mês</button>}
          {showFilters&&<div style={{position:"relative"}}><Search size={15} color={C.muted} style={{position:"absolute",left:11,top:10}} /><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar…" style={{padding:"8px 12px 8px 32px",width:180,borderRadius:8,border:`1px solid ${C.line}`,background:C.bg,fontSize:14.5,color:C.ink}} /></div>}
          <NotifBell count={notif.count} items={notif.items} />
        </header>

        {showFilters&&<FilterBar f={f} setF={setF} municipios={municipios} respOpts={respOpts} regimes={regimes}/>}

        <section className="appsection" style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",padding:"16px 24px 18px"}}>
          {act==="dashboard"&&<Dashboard me={me} isAdmin={isAdmin} comp={comp} canView={canView} statsOf={statsOf} inComp={inComp} getPD={getPD} go={setActive} db={db}/>}
          {act!=="dashboard"&&act!=="equipe"&&act!=="historico"&&act!=="rh"&&act!=="config"&&act!=="depts"&&act!=="regimes"&&act!=="estoque"&&act!=="certificados"&&act!=="motoboy"&&!act.startsWith("area:")&&<PermissionNote act={act} isAdmin={isAdmin} canManageCentral={canManageCentral} canEditDept={canEditDept} comp={comp} />}
          {act==="central"&&<Central list={centralList} inCompN={inComp.length} comp={comp} canManage={canManageCentral} sort={sort} setSort={setSort} regimes={regimes} openFull={(c)=>canManageCentral?setCadEdit(c):notify("Apenas Admin e Financeiro editam o cadastro.","deny")} editId={editId} draft={draft} setDraft={setDraft} startEdit={(c)=>{if(!canManageCentral)return notify("Apenas Admin e Financeiro editam o cadastro.","deny");setEditId(c.id);setDraft({...c});}} saveEdit={()=>{const orig=registry.find(c=>c.id===editId)||{};const patch={codigo:draft.codigo,razao:draft.razao,cnpj:draft.cnpj,regime:draft.regime,municipio:draft.municipio,situacao:draft.situacao,dataSituacao:draft.situacao==="Ativo"?"":draft.dataSituacao};const ch=Object.keys(patch).filter(k=>(orig[k]??"")!==(patch[k]??"")).map(k=>CLABEL[k]+": "+disp(orig[k])+" → "+disp(patch[k]));updateReg(editId,patch,`Cadastro · ${draft.razao}: ${ch.length?ch.join("; "):"sem alterações"}`);setEditId(null);notify("Cadastro atualizado.","ok");}} cancel={()=>setEditId(null)} delId={delId} setDelId={setDelId} doDelete={(id,razao)=>{mutate(prev=>({...prev,registry:prev.registry.filter(c=>c.id!==id)}),`Excluiu empresa · ${razao}`);setDelId(null);notify("Empresa excluída.","ok");}} notify={notify} />}
          {(act==="fiscal"||act==="pessoal")&&<><ModuleHeader kind={act} stats={modStats} comp={comp} />{view==="lista"?<DeptList kind={act} list={deptList} getPD={getPD} open={setOpenId} sort={sort} setSort={setSort} regimes={regimes} comp={comp} prazos={prazos} onBatchResp={batchAssignResp}/>:<DeptGrid kind={act} list={deptList} getPD={getPD} open={setOpenId} sort={sort} setSort={setSort} canEdit={(c)=>canEditFicha(c,act)} editCell={editCell} regimes={regimes}/>}</>}
          {OTHER_DEPTS.includes(act)&&<BlankDept dept={DEPTS.find(d=>d.key===act)} />}
          {act==="rh"&&<RHSuite rh={rh} saveRh={saveRh} canEdit={isAdmin||me.deptEdit==="rh"} notify={notify} />}
          {areaActive&&<GenericArea area={areaActive} canEdit={isAdmin} saveAreas={saveAreas} notify={notify} />}
          {act==="config"&&<Configuracoes areas={areas} saveAreas={saveAreas} labels={labels} saveLabels={saveLabels} startYm={startYm} setStartYm={setStartYm} notify={notify} go={setActive} />}
          {act==="depts"&&<DeptManager depts={DEPTS} areas={areas} saveAreas={saveAreas} labels={labels} saveLabels={saveLabels} hiddenDepts={hiddenDepts} saveHidden={saveHidden} notify={notify} go={setActive}/>}
          {act==="regimes"&&<RegimeManager regimes={regimes} saveRegimes={saveRegimes} prazos={prazos} savePrazos={savePrazos} notify={notify}/>}
          {act==="equipe"&&<Equipe employees={employees} registry={registry} onEdit={setEmpEdit} />}
          {act==="historico"&&<Historico log={db.log||[]} />}
      {act==="estoque"&&<Estoque me={me} active={act==="estoque"} />}
      {act==="certificados"&&<Certificados me={me} active={act==="certificados"} />}
      {act==="motoboy"&&<Motoboy db={db} saveMotoboy={saveMotoboy} me={me} notify={notify} />}
        </section>
      </main>

      {adding&&<EmpresaModal onClose={()=>setAdding(false)} nextCode={Math.max(0,...registry.map(c=>+c.codigo||0))+1} regimes={regimes} onSave={(nc)=>{mutate(prev=>({...prev,registry:[{...nc,id:Math.max(0,...prev.registry.map(c=>c.id))+1,respFiscal:"",respPessoal:""},...prev.registry]}),`Incluiu empresa · ${nc.razao}`);setAdding(false);notify("Empresa incluída.","ok");}} />}
      {cadEdit&&<EmpresaModal emp={cadEdit} onClose={()=>setCadEdit(null)} regimes={regimes} onSave={(nc)=>{updateReg(cadEdit.id,nc,`Cadastro completo atualizado · ${nc.razao}`);setCadEdit(null);notify("Cadastro atualizado.","ok");}} />}
      {opened&&(act==="fiscal"||act==="pessoal")&&<Ficha company={opened} pd={getPD(opened)} kind={act} comp={comp} canEdit={canEditFicha(opened,act)} canAssign={canAssignHere(act)} meName={me.nome} deptEmps={deptEmps(employees,act)} regimes={regimes} prazos={prazos} notes={notesFor(opened.id)} onAddNote={(t)=>addNote(opened.id,t)} onClose={()=>setOpenId(null)} onSave={saveFicha} />}
      {empEdit&&<EmpModal emp={empEdit} employees={employees} onClose={()=>setEmpEdit(null)} onSave={(e)=>{mutate(prev=>{let list;if(e.id){list=prev.employees.map(x=>x.id===e.id?e:x);}else{list=[...prev.employees,{...e,id:Math.max(0,...prev.employees.map(x=>x.id))+1}];}return {...prev,employees:list};},`Equipe · salvou ${e.nome}`);setEmpEdit(null);notify("Funcionário salvo.","ok");}} onDelete={(id,nome)=>{mutate(prev=>({...prev,employees:prev.employees.filter(x=>x.id!==id)}),`Equipe · removeu ${nome}`);setEmpEdit(null);notify("Funcionário removido.","ok");}} />}
      {showProfile&&<MeuPerfil me={me} onClose={()=>setShowProfile(false)} onSave={saveProfile} />}
      {toast&&<div style={{position:"absolute",bottom:18,left:"50%",transform:"translateX(-50%)",animation:"pop .2s ease",background:toast.kind==="deny"?C.red:C.navy,color:"#fff",padding:"11px 18px",borderRadius:10,fontSize:14.5,fontWeight:600,display:"flex",alignItems:"center",gap:8,boxShadow:"0 8px 24px rgba(12,22,64,.25)",zIndex:40}}>{toast.kind==="deny"?<Lock size={15}/>:<Check size={15}/>}{toast.m}</div>}
    </div>
  );
}

function NavItem({icon:Icon,label,hint,dot,on,onClick,badge,collapsed}){return <button onClick={onClick} className="navb" title={collapsed?label:undefined} style={{width:"100%",display:"flex",alignItems:"center",gap:collapsed?0:10,padding:collapsed?"9px 0":"9px 11px",justifyContent:collapsed?"center":"flex-start",margin:"2px 0",borderRadius:8,border:"none",cursor:"pointer",textAlign:"left",background:on?C.navySoft:"transparent",color:on?C.navy:C.body,fontSize:15,fontWeight:on?700:500,borderLeft:on?`3px solid ${C.navy}`:"3px solid transparent",position:"relative"}}><Icon size={16} color={on?C.navy:C.muted} />{!collapsed&&<span style={{flex:1}}>{label}</span>}{!collapsed&&hint&&<Pill bg={C.navySoft} fg={C.navy}>{hint}</Pill>}{badge>0&&<span style={{minWidth:18,height:18,borderRadius:9,background:C.red,color:"#fff",fontSize:11,fontWeight:800,display:"inline-flex",alignItems:"center",justifyContent:"center",padding:"0 4px",position:collapsed?"absolute":"static",top:collapsed?2:undefined,right:collapsed?2:undefined}}>{badge>99?"99+":badge}</span>}{!collapsed&&dot&&<Dot size={18} color={C.navy} />}</button>;}
function Splash(){return <div style={{display:"grid",placeItems:"center",height:"100vh",background:C.bg}}><style>{FONTS}</style><div style={{textAlign:"center",color:C.muted}}><Loader size={26} color={C.navy} style={{animation:"spin 1s linear infinite"}} /><div style={{marginTop:10,fontSize:14.5,fontWeight:600}}>Carregando dados…</div></div></div>;}

function Dashboard({me,isAdmin,comp,canView,statsOf,inComp,getPD,go,db}){
  const depts=["fiscal","pessoal"].filter(d=>canView(d));
  const [fd,setFd]=useState("todos");
  const [pendSort,setPendSort]=useState({key:"v",dir:1});
  const [showUrg,setShowUrg]=useState(false);
  const myName=me.nome;
  const cards=depts.map(d=>({d,label:DEPT_LABEL[d],st:statsOf(d,inComp)}));
  const regimes=db?.regimes||REGIME_SEED;

  // Próximo vencimento fiscal real, conforme prazos configurados por obrigação
  const prazos=db?.prazos||{};
  let nextDue=null,anyOverdue=false,nPend=0;
  inComp.forEach(c=>{const nd=fiscalNextDue(c,getPD(c),comp,regimes,prazos);if(nd){nPend++;if(nd.overdue)anyOverdue=true;if(!nextDue||nd.date<nextDue)nextDue=nd.date;}});
  const today=new Date();today.setHours(0,0,0,0);
  const daysLeft=nextDue?Math.round((nextDue-today)/864e5):null;
  const isLate=anyOverdue;const isUrg=!isLate&&daysLeft!==null&&daysLeft<=7;
  const deadLabel=!nextDue?"Sem pendências fiscais":isLate?"Vencimento(s) em atraso":isUrg?`Próx. vence em ${daysLeft}d`:`Próx. vencimento ${fmtDM(nextDue)}`;

  // Comparativo mês anterior
  const [yr,miStr]=comp.split("-");const mi=parseInt(miStr,10);
  const prevYM=mi===1?`${parseInt(yr)-1}-12`:`${yr}-${String(mi-1).padStart(2,"0")}`;
  const prevGetPD=(c)=>{const raw=db?.periods?.[prevYM]?.[c.id];return raw?mergePD(raw,c):defaultPD(c);};
  const prevAvg=(d)=>{let sum=0,n=0;inComp.forEach(c=>{const pd=prevGetPD(c);const ex=d==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);if(ex)return;sum+=(d==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c));n++;});return n>0?Math.round(sum/n):null;};

  // Sparkline: últimos 6 períodos
  const sparkDat=(d)=>COMPS.slice(-6).map(ym=>{
    const lst=(db?.registry||[]).filter(cc=>isActiveIn(cc,ym));
    if(!lst.length)return 0;let sum=0,n=0;
    lst.forEach(cc=>{const pd=db?.periods?.[ym]?.[cc.id];if(!pd)return;const ex=d==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,cc);if(ex)return;sum+=(d==="fiscal"?fiscalNum(pd,cc,regimes):pessoalNum(pd,cc));n++;});
    return n>0?Math.round(sum/n):0;
  });

  // Pendências com tarefas detalhadas
  const PSLTK=[["Holerites","holerites"],["VR/Cesta","vrCesta"],["RPA","alocRPA"],["FGTS","fgts"],["DARF/DAE","darfDae"],["DCOMP","dcomp"]];
  const pend=[];
  const useDepts=fd==="todos"?depts:[fd];
  useDepts.forEach(d=>{inComp.forEach(c=>{
    if(me.onlyAssigned&&!isAdmin){const r=d==="fiscal"?c.respFiscal:c.respPessoal;if(r!==myName)return;}
    const pd=getPD(c);const ex=d==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);const v=d==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c);
    if(!ex&&v<100){
      let tasks=[];
      if(d==="fiscal"&&pd.fiscal?.obrig)tasks=OBRIG.filter(([,k])=>{const _rj=(regimes||[]).find(r=>r.nome===c.regime)||null;if(_rj&&_rj.fiscal&&_rj.fiscal[k]==="nao_obrigada")return false;const ov=pd.fiscal.obrig[k]?.obrig||"";return ov==="Pendente"||!ov||ov===""||ov==="–";}).map(([l])=>l);
      else if(d==="pessoal"&&pd.pessoal)tasks=PSLTK.filter(([,k])=>{const ov=pd.pessoal[k];return ov==="Pendente"||!ov;}).map(([l])=>l);
      pend.push({c,d,v,tasks});
    }
  });});
  pend.sort((a,b)=>{if(pendSort.key==="v")return(a.v-b.v)*pendSort.dir;if(pendSort.key==="razao")return a.c.razao.localeCompare(b.c.razao)*pendSort.dir;if(pendSort.key==="d")return a.d.localeCompare(b.d)*pendSort.dir;return 0;});
  const filtPend=showUrg?pend.filter(p=>p.v<40):pend;

  return <div style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",gap:14,overflow:"auto"}}>
    {/* Banner compacto */}
    <div style={{background:C.navyDeep,borderRadius:12,padding:"10px 20px",display:"flex",alignItems:"center",gap:12,flexWrap:"wrap",flexShrink:0}}>
      <div style={{flex:1,display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
        <span style={{fontSize:14,color:"#b9c0d4"}}>Olá, {me.nome.split(" ")[0]} 👋</span>
        <span style={{color:"#445070",fontSize:14}}>·</span>
        <span style={{fontSize:13,color:"#8890a8"}}>{isAdmin?"Visão administrativa":`${depts.map(d=>DEPT_LABEL[d]).join(", ")||"–"}`}</span>
      </div>
      {pend.length>0&&<div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 11px",borderRadius:8,background:"rgba(217,96,96,.2)",border:"1px solid rgba(217,96,96,.35)"}}>
        <AlertCircle size={14} color="#e07c6e"/><span style={{fontSize:13,fontWeight:700,color:"#e07c6e"}}>{pend.length} pendência{pend.length!==1?"s":""}</span>
      </div>}
      <div style={{display:"flex",alignItems:"center",gap:5,padding:"5px 11px",borderRadius:8,background:isLate?"rgba(217,96,96,.15)":isUrg?"rgba(212,156,64,.15)":"rgba(255,255,255,.07)"}}>
        <Calendar size={13} color={isLate?"#e07c6e":isUrg?"#d49c40":"#8890a8"}/>
        <span style={{fontSize:12.5,fontWeight:600,color:isLate?"#e07c6e":isUrg?"#d49c40":"#8890a8"}}>{deadLabel}</span>
      </div>
    </div>

    {/* Cards KPI */}
    <div style={{display:"flex",gap:14,flexWrap:"wrap",flexShrink:0}}>
      {cards.length===0&&<div style={{color:C.muted,fontSize:14}}>Sem departamentos liberados.</div>}
      {cards.map(({d,label,st})=>{
        const prev=prevAvg(d);const diff=prev!==null?st.avg-prev:null;
        const spark=sparkDat(d);const isZ=st.avg===0&&inComp.length>0;
        return <div key={d} onClick={()=>go(d)}
          style={{flex:1,minWidth:280,background:C.card,border:`1px solid ${C.line}`,borderRadius:14,padding:"16px 18px",cursor:"pointer"}}
          onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 20px rgba(0,0,0,.1)"}
          onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
          <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:8}}>
            <span style={{fontSize:14,fontWeight:700,color:C.ink}}>{label}</span><ChevronRight size={16} color={C.muted}/>
          </div>
          <div style={{display:"flex",alignItems:"flex-end",gap:10,marginBottom:6}}>
            <span className="tnum" style={{fontSize:36,fontWeight:800,color:isZ?C.muted:barColor(st.avg),letterSpacing:-1.5,lineHeight:1}}>{isZ?"–":st.avg+"%"}</span>
            {diff!==null&&Math.abs(diff)>0&&<div style={{display:"flex",alignItems:"center",gap:2,paddingBottom:3,fontSize:12.5,fontWeight:700,color:diff>0?C.green:C.red}}>
              {diff>0?<ArrowUp size={13}/>:<ArrowDown size={13}/>}<span>{Math.abs(diff)}%</span>
            </div>}
            <div style={{flex:1,display:"flex",justifyContent:"flex-end",alignItems:"flex-end",paddingBottom:2}}><Sparkline data={spark}/></div>
          </div>
          <div style={{marginBottom:4}}><Bar pct={st.avg}/></div>
          {isZ&&<div style={{fontSize:11.5,color:C.muted,fontStyle:"italic",marginBottom:6}}>Período recém iniciado</div>}
          <div style={{display:"flex",gap:12,paddingTop:10,marginTop:4,borderTop:`1px solid ${C.line}`}}>
            <MiniStat n={st.tot} l="total" c={C.navy}/><MiniStat n={st.c100} l="concluídas" c={C.green}/><MiniStat n={st.pend} l="pendentes" c={C.amber}/><MiniStat n={st.na} l={d==="fiscal"?"sem mov.":"sem folha"} c={C.muted}/>
          </div>
          {d==="fiscal"&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"6px 14px",paddingTop:10,marginTop:8,borderTop:`1px solid ${C.line}`}}>
            {OBRIG.map(([lb,k])=>{const pct=st.obrig?.[k]||0;const col=pct>=75?C.green:pct>=40?C.amber:C.red;return <div key={k}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:11.5,marginBottom:2}}>
                <span style={{color:C.muted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:"68%"}} title={lb}>{lb}</span>
                <span className="tnum" style={{fontWeight:700,color:col,flexShrink:0,marginLeft:3}}>{pct}%</span>
              </div>
              <div style={{height:4,background:C.bg,borderRadius:2,overflow:"hidden"}}>
                <div style={{height:4,width:`${pct}%`,background:col,borderRadius:2,transition:"width .3s"}}/>
              </div>
            </div>;})}
          </div>}
        </div>;
      })}
    </div>

    {/* Tabela pendências */}
    <div style={{flex:1,minHeight:220,background:C.card,border:`1px solid ${C.line}`,borderRadius:14,display:"flex",flexDirection:"column",overflow:"hidden"}}>
      <div style={{padding:"11px 16px",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",gap:8,flexShrink:0,flexWrap:"wrap"}}>
        <AlertCircle size={15} color={pend.length>0?C.amber:C.green}/>
        <span style={{fontSize:14,fontWeight:700,color:C.ink}}>Pendências{me.onlyAssigned&&!isAdmin?" suas":""}</span>
        <span style={{fontSize:13,color:C.muted}}>· {filtPend.length}</span>
        <button onClick={()=>setShowUrg(v=>!v)} style={{padding:"4px 10px",borderRadius:6,border:`1px solid ${showUrg?C.red:C.line}`,background:showUrg?C.redSoft:C.card,color:showUrg?C.red:C.muted,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>⚠ Urgentes</button>
        <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:5,padding:"4px 10px",borderRadius:7,background:isLate?C.redSoft:isUrg?C.amberSoft:C.bg,border:`1px solid ${isLate?C.red:isUrg?C.amber:C.line}`}}>
          <Calendar size={12} color={isLate?C.red:isUrg?C.amber:C.muted}/>
          <span style={{fontSize:12.5,fontWeight:700,color:isLate?C.red:isUrg?C.amber:C.muted}}>{deadLabel}</span>
        </div>
        {depts.length>1&&<div style={{display:"flex",gap:4}}>{["todos",...depts].map(d=><button key={d} onClick={()=>setFd(d)} style={{padding:"5px 10px",borderRadius:6,border:`1px solid ${fd===d?C.navy:C.line}`,background:fd===d?C.navySoft:C.card,color:fd===d?C.navy:C.body,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>{d==="todos"?"Todos":DEPT_LABEL[d]}</button>)}</div>}
      </div>
      <div style={{flex:1,overflow:"auto"}}>
        <table style={tbl}><thead style={sticky}><tr style={trh}>
          <SortTH label="Empresa" k="razao" sort={pendSort} setSort={setPendSort}/>
          <SortTH label="Depto" k="d" sort={pendSort} setSort={setPendSort}/>
          <th style={th}>Tarefas pendentes</th>
          <SortTH label="Progresso" k="v" sort={pendSort} setSort={setPendSort}/>
        </tr></thead>
        <tbody>{filtPend.map(({c,d,v,tasks},i)=><tr key={i} className="rowh" style={{...trb,background:isLate&&v<30?`${C.red}12`:trb.background}}>
          <td style={td}><div style={{fontWeight:700,fontSize:13.5}}>{c.razao}</div><div style={{fontSize:11.5,color:C.muted}} className="tnum">{c.cnpj}</div></td>
          <td style={td}><Pill bg={C.navySoft} fg={C.navy} br="transparent">{DEPT_LABEL[d]}</Pill></td>
          <td style={td}>{tasks.length>0
            ?<div style={{display:"flex",gap:4,flexWrap:"wrap"}}>{tasks.slice(0,5).map(t=><span key={t} style={{padding:"2px 7px",borderRadius:5,background:C.amberSoft,border:`1px solid ${C.amber}44`,fontSize:11.5,color:C.amber,fontWeight:600,whiteSpace:"nowrap"}}>{t}</span>)}{tasks.length>5&&<span style={{fontSize:11.5,color:C.muted,alignSelf:"center"}}>+{tasks.length-5}</span>}</div>
            :<span style={{fontSize:12.5,color:C.muted,fontStyle:"italic"}}>Em andamento</span>}
          </td>
          <td style={td}><RowProg excl={null} prog={v}/></td>
        </tr>)}
        {filtPend.length===0&&<tr><td colSpan={4} style={{...td,textAlign:"center",color:pend.length>0?C.muted:C.green,padding:24,fontWeight:600}}>
          {pend.length>0&&showUrg?"Nenhuma pendência crítica (< 40%). ✓":"Tudo em dia nesta competência. ✓"}
        </td></tr>}
        </tbody></table>
      </div>
    </div>
  </div>;
}

function Sparkline({data}){
  if(!data||!data.length)return null;
  const max=Math.max(...data,1);const W=72,H=22;
  const bw=Math.max(4,Math.floor(W/data.length)-2);
  const sp=data.length>1?Math.max(1,Math.floor((W-bw*data.length)/(data.length-1))):0;
  return <svg width={W} height={H} style={{display:"block",overflow:"visible"}}>
    {data.map((v,i)=>{const bh=Math.max(2,Math.round((v/max)*H));return <rect key={i} x={i*(bw+sp)} y={H-bh} width={bw} height={bh} style={{fill:v>=75?"var(--c-green)":v>=40?"var(--c-amber)":"var(--c-muted)"}} rx={1.5} opacity={v===0?0.25:0.8}/>;})}</svg>;
}

function MiniStat({n,l,c}){return <div style={{minWidth:38}}><div className="tnum" style={{fontSize:16,fontWeight:800,color:c,lineHeight:1}}>{n}</div><div style={{fontSize:10.5,color:C.muted,marginTop:1,whiteSpace:"nowrap"}}>{l}</div></div>;}

function Mini({n,l,c}){return <div><div className="tnum" style={{fontSize:20,fontWeight:800,color:c}}>{n}</div><div style={{fontSize:12.5,color:C.muted}}>{l}</div></div>;}

function FilterBar({f,setF,municipios,respOpts,regimes=[]}){
  const sel=(key,label,opts)=>(<div style={{display:"flex",flexDirection:"column",gap:3}}><span style={{fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.4,textTransform:"uppercase"}}>{label}</span><select value={f[key]} onChange={e=>setF({...f,[key]:e.target.value})} style={{padding:"7px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:C.card,fontSize:14,fontWeight:600,color:C.ink,cursor:"pointer",minWidth:116}}><option value="todos">Todos</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select></div>);
  const dirty=Object.values(f).some(v=>v!=="todos");
  return <div style={{display:"flex",alignItems:"flex-end",gap:11,padding:"10px 24px",background:C.card,borderBottom:`1px solid ${C.line}`,flexShrink:0,flexWrap:"wrap"}}>
    <div style={{display:"flex",alignItems:"center",gap:6,color:C.navy,fontSize:14,fontWeight:700,marginBottom:7}}><Filter size={15} /> Filtros</div>
    {sel("regime","Regime",(regimes.length?regimes:REGIME_SEED).map(r=>r.nome))}{sel("municipio","Município",municipios)}{sel("situacao","Situação",["Ativo","Inativo","Bloqueada"])}
    {respOpts&&sel("resp","Responsável",respOpts)}
    {dirty&&<button onClick={()=>setF({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"})} style={{marginBottom:1,padding:"7px 12px",borderRadius:8,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontSize:14,fontWeight:600,cursor:"pointer"}}>Limpar</button>}
  </div>;
}
function PermissionNote({act,isAdmin,canManageCentral,canEditDept,comp}){
  if(act==="central")return <Note ok={canManageCentral} txt={canManageCentral?`Você inclui, edita, exclui e define a situação. Competência: ${compLabel(comp)}.`:"Somente leitura. Incluir, excluir e mudar situação são de Admin e Financeiro."} />;
  if(OTHER_DEPTS.includes(act))return null;
  const can=canEditDept(act);
  return <Note ok={can} txt={can?(isAdmin?`Administrador · você edita as fichas de ${compLabel(comp)}.`:`Você edita as fichas das empresas do seu departamento em ${compLabel(comp)} (conforme suas permissões).`):"Somente leitura. Apenas o gestor deste departamento (ou Admin) edita."} />;
}
function Note({ok,txt}){const Icon=ok?ShieldCheck:Eye;return <div style={{display:"flex",alignItems:"center",gap:9,background:ok?C.greenSoft:C.bg,border:`1px solid ${ok?"#cfe3d6":C.line}`,borderRadius:9,padding:"9px 13px",marginBottom:14,fontSize:14,color:C.ink,flexShrink:0}}><Icon size={15} color={ok?C.green:C.muted} /><span>{txt}</span></div>;}

function ModuleHeader({kind,stats,comp}){if(!stats)return null;
  return <div style={{display:"flex",gap:14,marginBottom:12,flexWrap:"wrap",flexShrink:0}}>
    <div style={{flex:1,minWidth:260,background:C.card,border:`1px solid ${C.line}`,borderRadius:12,padding:"14px 18px"}}>
      <div style={{display:"flex",alignItems:"baseline",justifyContent:"space-between"}}><span style={{fontSize:14,fontWeight:700,color:C.ink}}>Progresso médio · {DEPT_LABEL[kind]}</span><span className="tnum" style={{fontSize:29,fontWeight:800,color:barColor(stats.avg),letterSpacing:-1}}>{stats.avg}%</span></div>
      <div style={{margin:"8px 0 6px"}}><Bar pct={stats.avg} /></div>
      <div style={{fontSize:13,color:C.muted}}>{stats.tot} empresas · {stats.c100} a 100% · {stats.pend} pendentes · {stats.na} sem demanda · {compLabel(comp)}</div>
    </div>
    {kind==="fiscal"&&<div style={{flex:2,minWidth:320,display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(170px,1fr))",gap:9}}>{OBRIG.filter(([,k])=>!stats.applicableObrig||!stats.applicableObrig.length||stats.applicableObrig.includes(k)).map(([label,k])=>{const pct=stats.obrig[k]||0;const pc=pct>80?C.green:pct>=40?C.amber:C.red;return <div key={k} title={label} style={{background:C.card,border:`1px solid ${C.line}`,borderRadius:10,padding:"8px 11px",overflow:"hidden"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}><span style={{fontSize:12,fontWeight:700,color:C.ink,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:"68%"}}>{label}</span><span className="tnum" style={{fontSize:13,fontWeight:800,color:pc,flexShrink:0}}>{pct}%</span></div><Bar pct={pct} /></div>;})}</div>}
  </div>;
}

function SortTH({label,k,sort,setSort}){const active=sort.key===k;return <th style={{...th,cursor:"pointer",userSelect:"none"}} className="sorth" onClick={()=>setSort(active?{key:k,dir:-sort.dir}:{key:k,dir:1})}><span style={{display:"inline-flex",alignItems:"center",gap:3,color:active?C.navy:"inherit"}}>{label}{active?(sort.dir===1?<ArrowUp size={12}/>:<ArrowDown size={12}/>):<ArrowUp size={11} style={{opacity:.25}}/>}</span></th>;}

function Central({list,inCompN,comp,canManage,sort,setSort,editId,draft,setDraft,startEdit,saveEdit,cancel,delId,setDelId,doDelete,notify,regimes=[],openFull}){
  const inat=list.filter(c=>c.situacao!=="Ativo").length;
  const PER=50;
  const [page,setPage]=useState(0);
  const pages=Math.max(1,Math.ceil(list.length/PER));
  const cur=Math.min(page,pages-1);
  useEffect(()=>{setPage(0);},[list.length,sort.key,sort.dir]);
  const slice=list.slice(cur*PER,cur*PER+PER);
  return (<>
    <div style={{display:"flex",gap:14,marginBottom:12,flexWrap:"wrap",flexShrink:0}}>
      <Stat label="Total cadastradas" value={list.length} icon={Building2} />
      <Stat label={`Ativas em ${compLabel(comp)}`} value={inCompN} icon={Calendar} accent={C.green} />
      <Stat label="Inativas / Bloqueadas" value={inat} icon={Lock} accent={C.red} />
    </div>
    <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}><SortTH label="Cód." k="codigo" sort={sort} setSort={setSort} /><SortTH label="Razão social" k="razao" sort={sort} setSort={setSort} /><SortTH label="CNPJ" k="cnpj" sort={sort} setSort={setSort} /><th style={th}>Regime</th><th style={th}>Município</th><th style={th}>Situação</th><th style={th}>Desde</th><th style={th}></th></tr></thead>
      <tbody>{slice.map(c=>{const ed=editId===c.id;const del=delId===c.id;
        return <tr key={c.id} className="rowh" style={trb}>
          <td style={{...td,color:C.muted}} className="tnum">{ed?<input value={draft.codigo} onChange={e=>setDraft({...draft,codigo:e.target.value})} style={{...cellInp,width:64}} />:c.codigo}</td>
          <td style={td}>{ed?<input value={draft.razao} onChange={e=>setDraft({...draft,razao:e.target.value})} style={cellInp} />:<span style={{fontWeight:700}}>{c.razao}</span>}</td>
          <td style={{...td,color:C.body}} className="tnum">{ed?<input value={draft.cnpj} onChange={e=>setDraft({...draft,cnpj:e.target.value})} style={cellInp} />:c.cnpj}</td>
          <td style={td}>{ed?<select value={draft.regime} onChange={e=>setDraft({...draft,regime:e.target.value})} style={cellInp}>{[...(regimes.length?regimes:REGIME_SEED).map(r=>r.nome),"–"].map(o=><option key={o}>{o}</option>)}</select>:<Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime}</Pill>}</td>
          <td style={{...td,color:C.body}}>{ed?<input value={draft.municipio} onChange={e=>setDraft({...draft,municipio:e.target.value})} style={cellInp} />:c.municipio}</td>
          <td style={td}>{ed?<select value={draft.situacao} onChange={e=>setDraft({...draft,situacao:e.target.value})} style={cellInp}>{["Ativo","Inativo","Bloqueada"].map(o=><option key={o}>{o}</option>)}</select>:<StatusPill s={c.situacao} />}</td>
          <td style={{...td,color:C.body}} className="tnum">{ed?(draft.situacao!=="Ativo"?<input type="date" value={draft.dataSituacao||""} onChange={e=>setDraft({...draft,dataSituacao:e.target.value})} style={cellInp} />:<span style={{color:C.muted}}>–</span>):(c.situacao!=="Ativo"&&c.dataSituacao?c.dataSituacao:"–")}</td>
          <td style={{...td,textAlign:"right",whiteSpace:"nowrap"}}>{ed?<div style={{display:"flex",gap:6,justifyContent:"flex-end"}}><button onClick={saveEdit} style={iconBtn(C.navy)}><Check size={15}/></button><button onClick={cancel} style={iconBtn(C.muted)}><X size={15}/></button></div>:del?<div style={{display:"flex",gap:6,justifyContent:"flex-end",alignItems:"center"}}><span style={{fontSize:13,color:C.red,fontWeight:600}}>Excluir?</span><button onClick={()=>doDelete(c.id,c.razao)} style={iconBtn(C.red)}><Check size={15}/></button><button onClick={()=>setDelId(null)} style={iconBtn(C.muted)}><X size={15}/></button></div>:<div style={{display:"flex",gap:6,justifyContent:"flex-end"}}><button onClick={()=>openFull&&openFull(c)} style={iconBtn(C.navy)} title="Cadastro completo"><ClipboardList size={14}/></button><button onClick={()=>startEdit(c)} style={iconBtn(canManage?C.muted:"#c9cdd6")} title="Edição rápida">{canManage?<Pencil size={14}/>:<Lock size={13}/>}</button><button onClick={()=>canManage?setDelId(c.id):notify("Apenas Admin e Financeiro excluem.","deny")} style={iconBtn(canManage?C.red:"#c9cdd6")}>{canManage?<Trash2 size={14}/>:<Lock size={13}/>}</button></div>}</td>
        </tr>;})}
      {list.length===0&&<tr><td colSpan={8} style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma empresa com os filtros atuais.</td></tr>}
    </tbody></table></div>{pages>1&&<div style={{borderTop:`1px solid ${C.line}`,padding:"9px 14px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:10,flexShrink:0,fontSize:13.5,color:C.muted}}><span>Mostrando <b className="tnum" style={{color:C.body}}>{cur*PER+1}–{Math.min(cur*PER+PER,list.length)}</b> de <b className="tnum" style={{color:C.body}}>{list.length}</b></span><div style={{display:"flex",alignItems:"center",gap:6}}><button onClick={()=>setPage(p=>Math.max(0,Math.min(p,pages-1)-1))} disabled={cur===0} style={{display:"flex",alignItems:"center",gap:4,padding:"6px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:cur===0?C.bg:C.card,color:cur===0?C.muted:C.body,fontSize:13.5,fontWeight:700,cursor:cur===0?"not-allowed":"pointer"}}><ArrowLeft size={14}/>Anterior</button><span className="tnum" style={{fontWeight:700,color:C.ink,minWidth:64,textAlign:"center"}}>{cur+1} / {pages}</span><button onClick={()=>setPage(p=>Math.min(pages-1,Math.min(p,pages-1)+1))} disabled={cur>=pages-1} style={{display:"flex",alignItems:"center",gap:4,padding:"6px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:cur>=pages-1?C.bg:C.card,color:cur>=pages-1?C.muted:C.body,fontSize:13.5,fontWeight:700,cursor:cur>=pages-1?"not-allowed":"pointer"}}>Próxima<ArrowRight size={14}/></button></div></div>}</div></>);
}

const selSt={padding:"4px 6px",borderRadius:6,border:`1px solid ${C.line}`,background:C.field,fontSize:13.5,color:C.ink,cursor:"pointer",minWidth:96};
function DeptList({kind,list,getPD,open,sort,setSort,regimes=[],comp,prazos={},onBatchResp}){
  const [sel,setSel]=useState(new Set());const [quickId,setQuickId]=useState(null);
  const [progF,setProgF]=useState("todos");const [obligF,setObligF]=useState("todos");const [batchResp,setBatchResp]=useState("");
  const PROC_L={holerites:"Holerites",vrCesta:"VR/VT/Cesta",alocRPA:"Aloc. RPA",fgts:"FGTS",darfDae:"DARF/DAE",dcomp:"DCOMP"};
  const pc=(v)=>v>80?C.green:v>=40?C.amber:C.red;
  const applicObligs=kind==="fiscal"?[...new Set(list.flatMap(c=>{const rO=(regimes||[]).find(r=>r.nome===c.regime)||null;return OBRIG.filter(([,k])=>!(rO&&rO.fiscal&&rO.fiscal[k]==="nao_obrigada")).map(([,k])=>k);}))]:[]; 
  let filtered=list.filter(c=>{
    const pd=getPD(c);const excl=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);if(excl)return true;
    const prog=kind==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c);
    if(progF==="lt40"&&prog>=40)return false;if(progF==="lt80"&&prog>=80)return false;
    if(progF==="lt100"&&prog>=100)return false;if(progF==="done"&&prog<100)return false;
    if(kind==="fiscal"&&obligF!=="todos"){const rO=(regimes||[]).find(r=>r.nome===c.regime)||null;if(rO&&rO.fiscal&&rO.fiscal[obligF]==="nao_obrigada")return false;const ov=pd.fiscal?.obrig?.[obligF]?.obrig||"";if(ov==="Entregue"||ov==="N/A"||ov==="Não obrigada")return false;}
    return true;
  });
  if(sort.key==="_prog"){filtered=[...filtered].sort((a,b)=>{const pa=kind==="fiscal"?fiscalNum(getPD(a),a,regimes):pessoalNum(getPD(a),a);const pb=kind==="fiscal"?fiscalNum(getPD(b),b,regimes):pessoalNum(getPD(b),b);return(pa-pb)*sort.dir;});}
  const allSel=sel.size>0&&sel.size===filtered.length;
  const qComp=quickId?list.find(c=>c.id===quickId):null;const qPD=qComp?getPD(qComp):null;
  const today=new Date();today.setHours(0,0,0,0);
  const cols=kind==="fiscal"?10:9;
  return <div style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",overflow:"hidden",position:"relative"}}>
    <div style={{display:"flex",gap:8,padding:"8px 14px",background:C.card,borderBottom:`1px solid ${C.line}`,flexShrink:0,flexWrap:"wrap",alignItems:"center"}}>
      <select value={progF} onChange={e=>setProgF(e.target.value)} style={selSt}>
        <option value="todos">Todos os progressos</option><option value="lt40">Abaixo de 40%</option><option value="lt80">Abaixo de 80%</option><option value="lt100">Com pendências</option><option value="done">Concluídas (100%)</option>
      </select>
      {kind==="fiscal"&&applicObligs.length>0&&<select value={obligF} onChange={e=>setObligF(e.target.value)} style={selSt}>
        <option value="todos">Todas as obrigações</option>
        {OBRIG.filter(([,k])=>applicObligs.includes(k)).map(([l,k])=><option key={k} value={k}>{l} pendente</option>)}
      </select>}
      {(progF!=="todos"||obligF!=="todos")&&<button onClick={()=>{setProgF("todos");setObligF("todos");}} style={{...ghostBtn,fontSize:12.5,padding:"5px 9px"}}>✕ Limpar</button>}
      <span style={{fontSize:12.5,color:C.muted,marginLeft:"auto"}}>{filtered.length}{filtered.length<list.length?` / ${list.length}`:""} empresa{list.length!==1?"s":""}</span>
    </div>
    {sel.size>0&&<div style={{display:"flex",alignItems:"center",gap:8,padding:"8px 14px",background:C.navy,flexShrink:0,flexWrap:"wrap"}}>
      <span style={{fontSize:13,fontWeight:700,color:"#fff"}}>{sel.size} selecionada{sel.size!==1?"s":""}</span>
      <input value={batchResp} onChange={e=>setBatchResp(e.target.value)} placeholder="Atribuir responsável..." style={{padding:"5px 10px",borderRadius:7,border:"none",fontSize:13,flex:1,maxWidth:220,outline:"none"}}/>
      {batchResp.trim()&&<button onClick={()=>{onBatchResp&&onBatchResp(sel,batchResp.trim(),kind);setSel(new Set());setBatchResp("");}} style={{padding:"5px 12px",borderRadius:7,background:"#fff",color:C.navy,fontWeight:700,fontSize:13,border:"none",cursor:"pointer"}}>Aplicar</button>}
      <button onClick={()=>setSel(new Set())} style={{marginLeft:"auto",padding:"5px 10px",borderRadius:7,background:"rgba(255,255,255,.2)",color:"#fff",fontSize:13,border:"none",cursor:"pointer"}}>Limpar</button>
    </div>}
    <div style={{flex:1,overflow:"auto",minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:"0 0 11px 11px"}}>
      <table style={tbl}><thead style={sticky}><tr style={trh}>
        <th style={{...th,width:32,padding:"10px 8px"}}><input type="checkbox" checked={allSel} onChange={()=>setSel(allSel?new Set():new Set(filtered.map(c=>c.id)))} style={{cursor:"pointer"}}/></th>
        <SortTH label="Cód." k="codigo" sort={sort} setSort={setSort}/>
        <SortTH label="Razão social" k="razao" sort={sort} setSort={setSort}/>
        <SortTH label="CNPJ" k="cnpj" sort={sort} setSort={setSort}/>
        {kind==="fiscal"&&<SortTH label="Município" k="municipio" sort={sort} setSort={setSort}/>}
        <SortTH label={kind==="fiscal"?"Resp. Fiscal":"Resp. Pessoal"} k={kind==="fiscal"?"respFiscal":"respPessoal"} sort={sort} setSort={setSort}/>
        <SortTH label={kind==="fiscal"?"Regime":"Tipo folha"} k="regime" sort={sort} setSort={setSort}/>
        <th style={th}>Atualizado</th>
        <SortTH label="Progresso" k="_prog" sort={sort} setSort={setSort}/>
        <th style={{...th,textAlign:"right"}}>Ficha</th>
      </tr></thead>
      <tbody>{filtered.map((c,i)=>{
        const pd=getPD(c);const excl=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);
        const prog=kind==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c);
        const pCol=pc(prog);const isZero=prog===0&&!excl;const _nd=kind==="fiscal"?fiscalNextDue(c,pd,comp,regimes,prazos):null;const isOvd=!!(_nd&&_nd.overdue&&prog<100&&!excl);const isSel=sel.has(c.id);
        const ts=pd._meta?.ts;const tsLabel=ts?new Date(ts).toLocaleDateString("pt-BR",{day:"2-digit",month:"2-digit"}):"–";
        let tip="";if(!excl&&kind==="fiscal"){const rO=(regimes||[]).find(r=>r.nome===c.regime)||null;let dn=0,app=0;OBRIG.forEach(([,k])=>{if(rO&&rO.fiscal&&rO.fiscal[k]==="nao_obrigada")return;app++;const v=pd.fiscal?.obrig?.[k]?.obrig||"";if(v==="Entregue"||v==="N/A"||v==="Não obrigada")dn++;});tip=`${dn}/${app} concluídas${app-dn>0?` · ${app-dn} pendente${app-dn!==1?"s":""}`:""}`;}
        else if(!excl&&kind==="pessoal"){const dn=PROC.filter(k=>pd.pessoal?.[k]==="Concluído").length;tip=`${dn}/${PROC.length} processos concluídos`;}
        const rowBg=isSel?`${C.navy}14`:isOvd?`${C.red}08`:i%2===1?`${C.bg}60`:"transparent";
        return <tr key={c.id} className="rowh" style={{background:rowBg}}>
          <td style={{...td,width:32,padding:"8px"}} onClick={e=>e.stopPropagation()}><input type="checkbox" checked={isSel} onChange={()=>setSel(s=>{const n=new Set(s);n.has(c.id)?n.delete(c.id):n.add(c.id);return n;})} style={{cursor:"pointer"}}/></td>
          <td style={{...td,color:C.muted,fontSize:12.5}} className="tnum">{c.codigo}</td>
          <td style={{...td,cursor:"pointer"}} onClick={()=>setQuickId(quickId===c.id?null:c.id)}>
            <div style={{fontWeight:700,fontSize:13.5,color:C.ink}}>{c.razao}</div>
            {isOvd&&<div style={{fontSize:11,color:C.red,fontWeight:600}}>⚠ Prazo encerrado</div>}
            {isZero&&!isOvd&&<div style={{fontSize:11,color:C.muted,fontStyle:"italic"}}>Não iniciado</div>}
          </td>
          <td style={{...td,fontSize:13,color:C.body}} className="tnum">{c.cnpj}</td>
          {kind==="fiscal"&&<td style={{...td,fontSize:13,color:C.body}}>{c.municipio||"–"}</td>}
          <td style={{...td,fontSize:13,color:C.body}}>{(kind==="fiscal"?c.respFiscal:c.respPessoal)||<span style={{color:C.muted,fontStyle:"italic"}}>–</span>}</td>
          <td style={td}>{kind==="fiscal"?<Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime||"–"}</Pill>:<Pill bg={C.amberSoft} fg={C.amber} br="var(--c-line)">{pd.pessoal?.tipoFolha||c.tipoFolha||"–"}</Pill>}</td>
          <td style={{...td,fontSize:12,color:C.muted}} className="tnum">{tsLabel}</td>
          <td style={{...td,minWidth:140}} title={tip||undefined}>
            {excl?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill>
              :<div style={{cursor:tip?"help":"default"}}>
                <div style={{display:"flex",alignItems:"center",gap:7}}>
                  <div style={{flex:1,height:7,background:C.bg,borderRadius:4,overflow:"hidden",maxWidth:84}}><div style={{width:`${prog}%`,height:"100%",background:pCol,borderRadius:4,transition:"width .3s"}}/></div>
                  <span className="tnum" style={{fontSize:13,fontWeight:800,color:pCol,minWidth:34}}>{prog}%</span>
                </div>
              </div>}
          </td>
          <td style={{...td,textAlign:"right"}} onClick={()=>open(c.id)}>
            <span style={{display:"inline-flex",alignItems:"center",gap:4,padding:"5px 11px",borderRadius:7,background:isOvd?C.redSoft:C.navySoft,color:isOvd?C.red:C.navy,fontSize:13,fontWeight:700,cursor:"pointer",border:`1px solid ${isOvd?C.red+"33":C.navy+"22"}`,whiteSpace:"nowrap"}}>
              {isOvd&&<AlertCircle size={12}/>}Ficha<ChevronRight size={13}/>
            </span>
          </td>
        </tr>;})}
        {filtered.length===0&&<tr><td colSpan={cols} style={{...td,textAlign:"center",color:C.muted,padding:24}}>Nenhuma empresa com os filtros atuais.</td></tr>}
      </tbody></table>
    </div>
    {qComp&&qPD&&<div style={{position:"absolute",right:0,top:0,bottom:0,width:292,background:C.card,borderLeft:`2px solid ${C.navy}`,zIndex:10,display:"flex",flexDirection:"column",boxShadow:"-6px 0 24px rgba(0,0,0,.12)"}}>
      <div style={{padding:"12px 14px",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"flex-start",gap:8}}>
        <div style={{flex:1,minWidth:0}}><div style={{fontSize:13,fontWeight:800,color:C.ink,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{qComp.razao}</div><div style={{fontSize:12,color:C.muted,marginTop:3}} className="tnum">{qComp.cnpj}</div></div>
        <button onClick={()=>setQuickId(null)} style={iconBtn(C.muted)}><X size={15}/></button>
      </div>
      <div style={{flex:1,overflow:"auto",padding:"10px 14px"}}>
        {kind==="fiscal"&&<>
          <div style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.5,marginBottom:8}}>Obrigações Fiscais</div>
          {OBRIG.map(([lb,k])=>{const rO=(regimes||[]).find(r=>r.nome===qComp.regime)||null;const lok=rO&&rO.fiscal&&rO.fiscal[k]==="nao_obrigada";const ov=qPD.fiscal?.obrig?.[k]?.obrig||"–";const ovd=!lok&&ov!=="Entregue"&&ov!=="N/A"&&obrigDue(k,comp,prazos)<today;const dotC=lok?C.muted:ov==="Entregue"?C.green:ov==="N/A"?C.muted:ovd?C.red:C.amber;return <div key={k} style={{display:"flex",alignItems:"center",gap:8,padding:"7px 0",borderBottom:`1px solid ${C.line}`}}>
            <div style={{width:9,height:9,borderRadius:"50%",flexShrink:0,background:dotC}}/>
            <span style={{flex:1,fontSize:12.5,color:lok?C.muted:C.ink,fontStyle:lok?"italic":"normal",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}} title={lb}>{lb}{!lok&&ov!=="Entregue"&&ov!=="N/A"&&<span style={{color:ovd?C.red:C.muted,fontWeight:600}}> · vence {fmtDM(obrigDue(k,comp,prazos))}</span>}</span>
            <span style={{fontSize:12,fontWeight:700,color:dotC,flexShrink:0,marginLeft:4}}>{lok?"N/A":ov}</span>
          </div>;})}
          <div style={{marginTop:10,paddingTop:8,borderTop:`1px solid ${C.line}`,display:"flex",gap:14,fontSize:12.5,color:C.muted}}><span>Concluído: <b style={{color:C.ink}}>{qPD.fiscal?.fiscalConcluido||"Não"}</b></span><span>Conf.: <b style={{color:C.ink}}>{qPD.fiscal?.fiscalConfirmacao||"Não"}</b></span></div>
        </>}
        {kind==="pessoal"&&<>
          <div style={{fontSize:11,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.5,marginBottom:8}}>Processos Pessoal</div>
          {PROC.map(k=>{const ov=qPD.pessoal?.[k]||"–";const done=ov==="Concluído";const dC=done?C.green:C.amber;return <div key={k} style={{display:"flex",alignItems:"center",gap:8,padding:"7px 0",borderBottom:`1px solid ${C.line}`}}>
            <div style={{width:9,height:9,borderRadius:"50%",flexShrink:0,background:dC}}/>
            <span style={{flex:1,fontSize:12.5,color:C.ink}}>{PROC_L[k]||k}</span>
            <span style={{fontSize:12,fontWeight:700,color:dC}}>{ov}</span>
          </div>;})}
        </>}
        <div style={{marginTop:12}}><button onClick={()=>{open(qComp.id);setQuickId(null);}} style={{...primBtn(),width:"100%",justifyContent:"center"}}>Abrir ficha completa <ChevronRight size={14}/></button></div>
      </div>
    </div>}
  </div>;
}
function DeptGrid({kind,list,getPD,open,sort,setSort,canEdit,editCell,regimes=[]}){
  const stL={position:"sticky",left:0,zIndex:2,background:C.card,boxShadow:"2px 0 0 "+C.line};
  const stLH={position:"sticky",left:0,top:0,zIndex:4,background:C.bg,boxShadow:"2px 0 0 "+C.line};
  const Cell=({val,opts,can,onCh})=> can?<select value={val} onChange={e=>onCh(e.target.value)} style={selSt}>{opts.map(o=><option key={o}>{o}</option>)}</select>:<StatusPill s={val} />;
  const PL={holerites:"Holerites",vrCesta:"VR/Cesta",alocRPA:"RPA",fgts:"FGTS",darfDae:"DARF/DAE",dcomp:"DCOMP"};
  const cols=kind==="fiscal"?[{l:"Município",w:120},{l:"Resp.",w:110},{l:"Regime",w:140},...OBRIG.map(([l])=>({l,w:118})),{l:"Concluído",w:90},{l:"Confirm.",w:90},{l:"Progresso",w:120}]
    :[{l:"Resp.",w:110},{l:"Tipo folha",w:130},...PROC.map(k=>({l:PL[k],w:108})),{l:"Retific.",w:90},{l:"Concluído",w:90},{l:"Confirm.",w:90},{l:"Progresso",w:120}];
  const SortLbl=({label,k})=>{const a=sort.key===k;return <span onClick={()=>setSort(a?{key:k,dir:-sort.dir}:{key:k,dir:1})} style={{cursor:"pointer",color:a?C.navy:"inherit",display:"inline-flex",alignItems:"center",gap:2}}>{label}{a?(sort.dir===1?<ArrowUp size={11}/>:<ArrowDown size={11}/>):null}</span>;};
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}>
    <div style={{flex:1,overflow:"auto"}}><table style={{borderCollapse:"collapse",fontSize:14,whiteSpace:"nowrap"}}>
      <thead style={{position:"sticky",top:0,zIndex:3}}><tr style={trh}>
        <th style={{...th,...stLH,minWidth:236}}><span style={{display:"inline-flex",gap:10}}><SortLbl label="Cód." k="codigo" /><SortLbl label="Empresa" k="razao" /></span></th>
        {cols.map(c=><th key={c.l} style={{...th,minWidth:c.w}}>{c.l}</th>)}<th style={th}></th>
      </tr></thead>
      <tbody>{list.map(c=>{const pd=getPD(c);const excl=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);const prog=kind==="fiscal"?fiscalNum(pd,c,regimes):pessoalNum(pd,c);const pColG=prog>80?C.green:prog>=40?C.amber:C.red;const can=canEdit(c)&&!excl;const set=(mut)=>editCell(c,kind,mut);const rObj=(regimes||[]).find(r=>r.nome===c.regime)||null;const obLok=(k)=>!!(rObj&&rObj.fiscal&&rObj.fiscal[k]==="nao_obrigada");
        return <tr key={c.id} className="rowh" style={trb}>
          <td style={{...td,...stL}}><div style={{fontWeight:700,whiteSpace:"normal",maxWidth:240,overflow:"hidden",textOverflow:"ellipsis"}}>{c.razao}</div><div style={{fontSize:12,color:C.muted}} className="tnum">cód {c.codigo} · {c.cnpj}</div></td>
          {kind==="fiscal"?<>
            <td style={{...td,color:C.body}}>{c.municipio||"–"}</td><td style={{...td,color:C.body}}>{c.respFiscal||"–"}</td><td style={td}><Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime}</Pill></td>
            {excl?<td colSpan={OBRIG.length+2} style={{...td,textAlign:"center"}}><Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill></td>:<>
              {OBRIG.map(([l,k])=>{const lok=obLok(k);return <td key={k} style={td}>{lok?<span style={{fontSize:12,color:C.muted,fontStyle:"italic",whiteSpace:"nowrap"}}>Não obrig.</span>:<Cell val={pd.fiscal.obrig[k].obrig} opts={OBRIG_ST} can={can&&!lok} onCh={v=>set(p=>{p.fiscal.obrig[k].obrig=v;return p;})}/>}</td>;})}
              <td style={td}><Cell val={pd.fiscal.fiscalConcluido} opts={SN} can={can} onCh={v=>set(p=>{p.fiscal.fiscalConcluido=v;return p;})} /></td>
              <td style={td}><Cell val={pd.fiscal.fiscalConfirmacao} opts={SN} can={can} onCh={v=>set(p=>{p.fiscal.fiscalConfirmacao=v;return p;})} /></td></>}
            <td style={td}><RowProg excl={excl} prog={prog} /></td></>:<>
            <td style={{...td,color:C.body}}>{c.respPessoal||"–"}</td><td style={td}><Pill bg={C.amberSoft} fg={C.amber} br="var(--c-line)">{pd.pessoal.tipoFolha||c.tipoFolha}</Pill></td>
            {excl?<td colSpan={PROC.length+3} style={{...td,textAlign:"center"}}><Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill></td>:<>
              {PROC.map(k=><td key={k} style={td}><Cell val={pd.pessoal[k]} opts={STAT_OPTS} can={can} onCh={v=>set(p=>{p.pessoal[k]=v;return p;})} /></td>)}
              <td style={td}><Cell val={pd.pessoal.retificacao} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.retificacao=v;return p;})} /></td>
              <td style={td}><Cell val={pd.pessoal.pessoalConcluido} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.pessoalConcluido=v;return p;})} /></td>
              <td style={td}><Cell val={pd.pessoal.confEnvio} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.confEnvio=v;return p;})} /></td></>}
            <td style={td}><RowProg excl={excl} prog={prog} /></td></>}
          <td style={td}><button onClick={()=>open(c.id)} style={{display:"inline-flex",alignItems:"center",gap:3,color:C.navy,fontSize:13.5,fontWeight:700,background:"none",border:"none",cursor:"pointer"}}>Ficha <ChevronRight size={13} /></button></td>
        </tr>;})}
        {list.length===0&&<tr><td style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma empresa.</td></tr>}
      </tbody></table></div></div>;
}
function BlankDept({dept}){const Icon=dept.icon;return <div style={{flex:1,display:"grid",placeItems:"center",textAlign:"center",color:C.muted}}><div><div style={{width:54,height:54,borderRadius:14,background:C.card,border:`1px solid ${C.line}`,display:"grid",placeItems:"center",margin:"0 auto 14px"}}><Icon size={24} color={C.grey} /></div><div style={{fontSize:18,fontWeight:800,color:C.ink}}>Módulo {dept.label}</div><div style={{fontSize:14.5,maxWidth:380,marginTop:6,lineHeight:1.5}}>Ainda não estruturado. Envie a planilha deste departamento que montamos a ficha completa.</div></div></div>;}

function EmpSel({v,set,emps,disabled}){return <select value={v||""} disabled={disabled} onChange={e=>set(e.target.value)} style={{...cellInp,cursor:disabled?"not-allowed":"pointer"}}><option value="">– sem –</option>{emps.map(n=><option key={n}>{n}</option>)}</select>;}
function Field({row,val,onChange,disabled}){const base={width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:disabled?C.bg:C.field,fontSize:14.5,color:C.ink};
  if(row.t==="sel"||row.t==="status"){const opts=row.t==="status"?STAT_OPTS:row.o;return <select value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={{...base,cursor:disabled?"not-allowed":"pointer"}}>{opts.map(o=><option key={o}>{o}</option>)}</select>;}
  if(row.t==="date") return <input type="date" value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={base} />;
  if(row.t==="money") return <input type="number" step="0.01" value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value===""?"":Number(e.target.value))} style={base} placeholder="0,00" />;
  return <input value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={base} />;}

function NotasPanel({notes,onAdd}){
  const [t,setT]=useState("");
  const list=[...notes].reverse();
  return <div>
    <div style={secT}>Notas e observações da empresa</div>
    <div style={{fontSize:12.5,color:C.muted,marginBottom:10}}>Anotações livres, não vinculadas à competência. Visíveis para quem abre esta ficha.</div>
    {onAdd&&<div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:16}}>
      <textarea value={t} onChange={e=>setT(e.target.value)} placeholder="Escreva uma nota…" style={{width:"100%",minHeight:70,padding:"10px 12px",borderRadius:9,border:`1px solid ${C.line}`,background:C.field,fontSize:14,color:C.ink,resize:"vertical",fontFamily:"inherit"}} />
      <div style={{display:"flex",justifyContent:"flex-end"}}><button onClick={()=>{if(t.trim()){onAdd(t);setT("");}}} disabled={!t.trim()} style={{padding:"8px 16px",borderRadius:9,border:"none",background:t.trim()?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:14,cursor:t.trim()?"pointer":"not-allowed",display:"flex",alignItems:"center",gap:7}}><Plus size={15}/> Adicionar nota</button></div>
    </div>}
    {list.length===0&&<div style={{padding:"18px",textAlign:"center",color:C.muted,fontSize:13.5,background:C.bg,borderRadius:9,border:`1px dashed ${C.line}`}}>Nenhuma nota registrada ainda.</div>}
    {list.map((n,i)=><div key={i} style={{background:C.card,border:`1px solid ${C.line}`,borderRadius:10,padding:"11px 14px",marginBottom:9}}><div style={{fontSize:14,color:C.ink,whiteSpace:"pre-wrap",lineHeight:1.5}}>{n.text}</div><div style={{fontSize:12,color:C.muted,marginTop:6}}>{n.by} · {fmtDT(n.ts)}</div></div>)}
  </div>;
}

function Ficha({company,pd,kind,comp,canEdit,canAssign,meName,deptEmps,regimes=[],prazos={},notes=[],onAddNote,onClose,onSave}){
  const [sm,setSm]=useState(!!pd.semMovimento);
  const regObj=(regimes||[]).find(r=>r.nome===company.regime)||null;
  const obrigLocked=(key)=>!!(regObj&&regObj.fiscal&&regObj.fiscal[key]==="nao_obrigada");
  const [ff,setFf]=useState(()=>{const init=JSON.parse(JSON.stringify(pd.fiscal));if(regObj&&regObj.fiscal)OBRIG.forEach(([,k])=>{if(regObj.fiscal[k]==="nao_obrigada")init.obrig[k].obrig="Não obrigada";});return init;});
  const [pf,setPf]=useState(()=>JSON.parse(JSON.stringify(pd.pessoal)));
  const [resp,setResp]=useState(kind==="fiscal"?company.respFiscal:company.respPessoal);
  const SECTIONS=kind==="fiscal"?FISCAL_FORM:PESSOAL_FORM;
  const setF=(k,v)=>setFf(o=>({...o,[k]:v})); const setP=(k,v)=>setPf(o=>({...o,[k]:v}));
  const setObrig=(key,sub,v)=>setFf(o=>({...o,obrig:{...o.obrig,[key]:{...o.obrig[key],[sub]:v}}}));
  const setNested=(grp,sub,v)=>setFf(o=>({...o,[grp]:{...o[grp],[sub]:v}}));
  const prog=kind==="fiscal"?(sm?100:fiscalNum({semMovimento:sm,fiscal:ff})):((sm||(pf.tipoFolha==="SEM FOLHA"))?100:pessoalNum({semMovimento:sm,pessoal:pf},company));
  const excl=kind==="fiscal"?(sm?"S/M":null):(sm?"S/M":(pf.tipoFolha==="SEM FOLHA"?"Sem folha":null));
  const dirty=canEdit||canAssign;
  const save=()=>{const regPatch=(canAssign)?(kind==="fiscal"?(resp!==company.respFiscal?{respFiscal:resp}:{}):(resp!==company.respPessoal?{respPessoal:resp}:{})):{};const newPD={semMovimento:sm,_meta:{by:meName,at:Date.now()},fiscal:kind==="fiscal"?ff:pd.fiscal,pessoal:kind==="pessoal"?pf:pd.pessoal};onSave(regPatch,newPD);};
  const [tabIdx,setTabIdx]=useState(0);
  const TABS=["Geral",...SECTIONS.map(s=>s.sec),...(kind==="fiscal"?["Obrigações","Assinaturas"]:[]),"Notas"];
  const tab=Math.min(tabIdx,TABS.length-1);
  const obrigTab=1+SECTIONS.length, assinTab=2+SECTIONS.length, notesTab=TABS.length-1;
  const tabBtn=(i)=>({padding:"7px 13px",border:"none",borderBottom:`2px solid ${tab===i?C.navy:"transparent"}`,background:"none",color:tab===i?C.navy:C.muted,fontSize:13.5,fontWeight:tab===i?800:600,cursor:"pointer",whiteSpace:"nowrap"});
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.4)",zIndex:30,display:"flex",justifyContent:"flex-end"}}>
    <div onClick={e=>e.stopPropagation()} style={{width:580,maxWidth:"95%",height:"100%",background:C.bg,animation:"slin .22s ease",display:"flex",flexDirection:"column"}}>
      <div style={{background:C.card,borderBottom:`1px solid ${C.line}`,padding:"15px 22px",display:"flex",alignItems:"center",gap:12,flexShrink:0}}>
        <div style={{flex:1,minWidth:0}}><div style={{fontSize:12,color:C.muted,letterSpacing:1,textTransform:"uppercase",fontWeight:700}}>Ficha {kind==="fiscal"?"Fiscal":"Pessoal"} · {compLabel(comp)} · cód {company.codigo}</div>
          <div style={{fontSize:19,fontWeight:800,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{company.razao}</div>
          <div style={{fontSize:13,color:C.muted}} className="tnum">{company.cnpj} · {company.regime} · {company.municipio}</div></div>
        <div style={{textAlign:"center"}}>{excl?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill>:<><div className="tnum" style={{fontSize:24.5,fontWeight:800,color:barColor(prog)}}>{prog}%</div><div style={{width:60}}><Bar pct={prog} /></div></>}</div>
        <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button>
      </div>
      {!canEdit&&<div style={{margin:"12px 22px 0",background:C.bg,border:`1px solid ${C.line}`,borderRadius:9,padding:"9px 13px",fontSize:14,color:C.muted,display:"flex",gap:8,alignItems:"center",flexShrink:0}}><Eye size={15} /> Somente leitura · esta empresa não está atribuída a você (ou você não edita este departamento).</div>}
      {pd._meta&&<div style={{margin:"12px 22px 0",fontSize:13,color:C.muted,flexShrink:0}}>Última alteração: <b style={{color:C.body}}>{pd._meta.by}</b> em {fmtDT(pd._meta.at)}</div>}
      <div style={{display:"flex",gap:2,padding:"0 16px",borderBottom:`1px solid ${C.line}`,background:C.card,overflowX:"auto",flexShrink:0}}>{TABS.map((t,i)=><button key={i} onClick={()=>setTabIdx(i)} style={tabBtn(i)}>{t}</button>)}</div>
      <div style={{flex:1,overflow:"auto",padding:"14px 22px 20px"}}>
        {tab===0&&<>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
          <div><label style={fl}>Responsável ({kind==="fiscal"?"Fiscal":"Pessoal"})</label><EmpSel v={resp} set={setResp} emps={deptEmps} disabled={!canAssign} />{!canAssign&&<div style={{fontSize:12,color:C.muted,marginTop:3}}>Só quem tem permissão de atribuição altera.</div>}</div>
        </div>
        {kind==="fiscal"&&<div style={{background:sm?C.navySoft:C.bg,border:`1px solid ${sm?"#dbe2f0":C.line}`,borderRadius:10,padding:"11px 14px",display:"flex",alignItems:"center",gap:10,marginBottom:14}}><input type="checkbox" checked={sm} disabled={!canEdit} onChange={e=>setSm(e.target.checked)} style={{width:16,height:16,cursor:canEdit?"pointer":"not-allowed"}} /><div style={{flex:1}}><div style={{fontSize:14.5,fontWeight:700,color:C.ink}}>Sem movimento no período (S/M)</div><div style={{fontSize:13,color:C.muted}}>O Pessoal verá isso e a empresa sai do cálculo de progresso.</div></div>{sm&&<Pill bg={C.navy} fg="#fff">S/M</Pill>}</div>}
        {kind==="pessoal"&&<div style={{background:C.navySoft,border:"1px solid #dbe2f0",borderRadius:10,padding:"11px 14px",marginBottom:14}}><div style={{fontSize:12.5,fontWeight:700,color:C.navy,letterSpacing:.4,textTransform:"uppercase",marginBottom:6,display:"flex",alignItems:"center",gap:6}}><Eye size={13} /> Vindo do Fiscal (somente leitura)</div><div style={{display:"flex",gap:18,fontSize:14,color:C.ink}}><span>EFD REINF: <StatusPill s={pd.fiscal.obrig.efdreinf.obrig} /></span>{pd.fiscal.obrig.efdreinf.data&&<span style={{color:C.muted}}>em {pd.fiscal.obrig.efdreinf.data}</span>}{pd.semMovimento&&<span><b>SEM MOVIMENTO</b></span>}</div></div>}
        </>}
        {SECTIONS.map((s,si)=>tab===si+1&&<div key={s.sec} style={{marginBottom:16}}><div style={secT}>{s.sec}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px 14px"}}>{s.rows.map(r=><div key={r.k}><label style={fl}>{r.l}</label><Field row={r} val={(kind==="fiscal"?ff:pf)[r.k]} disabled={!canEdit} onChange={v=>(kind==="fiscal"?setF:setP)(r.k,v)} /></div>)}</div></div>)}
        {kind==="fiscal"&&tab===obrigTab&&<>
          <div style={secT}>Obrigações acessórias</div>
          <div style={{background:C.card,border:`1px solid ${C.line}`,borderRadius:10,overflow:"hidden"}}><table style={{...tbl,fontSize:14}}><thead><tr style={trh}><th style={th}>Obrigação</th><th style={th}>Status</th><th style={th}>Vence em</th><th style={th}>Data</th><th style={th}>RET</th></tr></thead><tbody>{OBRIG.map(([label,key])=>{const _due=obrigDue(key,comp,prazos);const _today=new Date();_today.setHours(0,0,0,0);const _ovStatus=ff.obrig[key].obrig;const _ovd=!obrigLocked(key)&&_ovStatus!=="Entregue"&&_ovStatus!=="N/A"&&_due<_today;return <tr key={key} style={trb}><td style={{...td,fontWeight:600}}>{label}{key==="efdreinf"&&<span style={{fontSize:11,color:C.navy,marginLeft:6}}>→ Pessoal</span>}</td><td style={{...td,width:140}}>{obrigLocked(key)?<span style={{display:"inline-block",padding:"5px 8px",fontSize:12.5,color:C.muted,fontStyle:"italic"}}>Não obrigada</span>:<select value={ff.obrig[key].obrig} disabled={!canEdit} onChange={e=>setObrig(key,"obrig",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:14,color:C.ink,cursor:canEdit?"pointer":"not-allowed"}}>{OBRIG_ST.map(o=><option key={o}>{o}</option>)}</select>}</td><td style={{...td,width:84,fontSize:12.5,fontWeight:700,color:obrigLocked(key)?C.muted:_ovd?C.red:C.body}} className="tnum">{obrigLocked(key)?"–":fmtDM(_due)}</td><td style={{...td,width:140}}><input type="date" value={ff.obrig[key].data} disabled={!canEdit} onChange={e=>setObrig(key,"data",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:13.5,color:C.ink}} /></td><td style={{...td,width:80}}><input value={ff.obrig[key].ret} disabled={!canEdit} onChange={e=>setObrig(key,"ret",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:13.5,color:C.ink}} placeholder="–" /></td></tr>;})}</tbody></table></div>
        </>}
        {kind==="fiscal"&&tab===assinTab&&<>
          {[["coordFiscal","Coordenadora Fiscal"],["depContabil","Departamento Contábil"]].map(([grp,t])=><div key={grp} style={{marginTop:16}}><div style={secT}>{t}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1.4fr",gap:12}}><div><label style={fl}>Finalizada</label><select value={ff[grp].fin} disabled={!canEdit} onChange={e=>setNested(grp,"fin",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:14.5,color:C.ink,cursor:canEdit?"pointer":"not-allowed"}}>{SN.map(o=><option key={o}>{o}</option>)}</select></div><div><label style={fl}>Data</label><input type="date" value={ff[grp].data} disabled={!canEdit} onChange={e=>setNested(grp,"data",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:14.5,color:C.ink}} /></div><div><label style={fl}>Observação</label><input value={ff[grp].obs} disabled={!canEdit} onChange={e=>setNested(grp,"obs",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?C.field:C.bg,fontSize:14.5,color:C.ink}} /></div></div></div>)}
        </>}
        {tab===notesTab&&<NotasPanel notes={notes} onAdd={onAddNote} />}
      </div>
      {dirty&&<div style={{background:C.card,borderTop:`1px solid ${C.line}`,padding:"12px 22px",display:"flex",gap:10,justifyContent:"flex-end",flexShrink:0}}><button onClick={onClose} style={{padding:"10px 18px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:15,cursor:"pointer"}}>Cancelar</button><button onClick={save} style={{padding:"10px 20px",borderRadius:9,border:"none",background:C.navy,color:"#fff",fontWeight:700,fontSize:15,cursor:"pointer",display:"flex",alignItems:"center",gap:7}}><Save size={16} /> Salvar</button></div>}
    </div></div>;
}

function Equipe({employees,registry,onEdit}){
  const carga=(nome,d)=>registry.filter(c=>(d==="fiscal"?c.respFiscal:c.respPessoal)===nome).length;
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}>{["Funcionário","Cargo","Departamento","Usuário","Acesso","Carga","Status",""].map(h=><th key={h} style={th}>{h}</th>)}</tr></thead>
    <tbody>{employees.map(e=>{const acc=e.isAdmin?"Administrador":[e.canCentral?"Cadastro":null,e.deptEdit?("Edita "+DEPT_LABEL[e.deptEdit]):null,e.onlyAssigned?"(só atribuídas)":null,e.canAssign?"atribui":null].filter(Boolean).join(" · ")||"Visualização";
      return <tr key={e.id} className="rowh" style={trb}>
      <td style={td}><div style={{fontWeight:700}}>{e.nome}</div><div style={{fontSize:12.5,color:C.muted}}>{e.email||"–"}</div></td>
      <td style={{...td,color:C.body}}>{e.cargo||"–"}</td>
      <td style={td}>{e.dept==="admin"?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">Administração</Pill>:<Pill bg={C.bg} fg={C.body} br={C.line}>{DEPT_LABEL[e.dept]||"–"}</Pill>}</td>
      <td style={{...td,color:C.body}} className="tnum">{e.user}</td>
      <td style={{...td,color:C.body,fontSize:13}}>{acc}</td>
      <td style={{...td,color:C.muted,fontSize:13.5}} className="tnum">{e.dept==="fiscal"?carga(e.nome,"fiscal")+" emp.":e.dept==="pessoal"?carga(e.nome,"pessoal")+" emp.":"–"}</td>
      <td style={td}><StatusPill s={e.ativo?"Ativo":"Inativo"} /></td>
      <td style={{...td,textAlign:"right"}}><button onClick={()=>onEdit(e)} style={iconBtn(C.muted)}><Pencil size={14} /></button></td>
    </tr>;})}</tbody></table></div></div>;
}

function Historico({log}){
  const csv=()=>downloadCSV("historico_alteracoes",["Data / hora","Usuário","Ação"],[...log].reverse().map(e=>[fmtDT(e.ts),e.user,e.action]));
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{padding:"12px 18px",borderBottom:`1px solid ${C.line}`,fontSize:14,color:C.muted,flexShrink:0,display:"flex",alignItems:"center",gap:10}}><span style={{flex:1}}>Registro de alterações (mais recentes primeiro) · controle de segurança. <b style={{color:C.body}}>{log.length}</b> registro{log.length!==1?"s":""}.</span><button onClick={csv} style={ghostBtn}><Download size={14}/> Exportar CSV</button></div><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}><th style={th}>Data / hora</th><th style={th}>Usuário</th><th style={th}>Ação</th></tr></thead>
    <tbody>{[...log].reverse().map((e,i)=><tr key={i} style={trb}><td style={{...td,color:C.body}} className="tnum">{fmtDT(e.ts)}</td><td style={{...td,fontWeight:700}}>{e.user}</td><td style={{...td,color:C.body}}>{e.action}</td></tr>)}
    {log.length===0&&<tr><td colSpan={3} style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma alteração registrada ainda.</td></tr>}</tbody></table></div></div>;
}

function fileToAvatar(file,cb){if(!file)return;const r=new FileReader();r.onload=()=>{const img=new Image();img.onload=()=>{const max=160;let w=img.width,h=img.height;const sc=Math.min(1,max/Math.max(w,h));w=Math.round(w*sc);h=Math.round(h*sc);try{const cv=document.createElement("canvas");cv.width=w;cv.height=h;cv.getContext("2d").drawImage(img,0,0,w,h);cb(cv.toDataURL("image/jpeg",0.82));}catch(e){cb(r.result);}};img.onerror=()=>cb(r.result);img.src=r.result;};r.readAsDataURL(file);}
function Avatar({nome,src,size=32,fs=14.5}){return src?<img src={src} alt="" style={{width:size,height:size,borderRadius:8,objectFit:"cover",flexShrink:0}}/>:<div style={{width:size,height:size,borderRadius:8,background:C.navy,color:"#fff",display:"grid",placeItems:"center",fontWeight:700,fontSize:fs,flexShrink:0}}>{((nome||"?").trim()[0]||"?").toUpperCase()}</div>;}

function EmpModal({emp,employees,onClose,onSave,onDelete}){
  const isNew=!emp.id;
  const [v,setV]=useState(()=>({id:emp.id,nome:emp.nome||"",cpf:emp.cpf||"",email:emp.email||"",cargo:emp.cargo||"",dept:emp.dept&&emp.dept!=="admin"?emp.dept:"fiscal",user:emp.user||"",avatar:emp.avatar||"",isAdmin:!!emp.isAdmin,canCentral:!!emp.canCentral,canAssign:!!emp.canAssign,onlyAssigned:emp.onlyAssigned!==false?!!emp.onlyAssigned:false,view:emp.view?emp.view.slice():VIEW_ALL.slice(),ativo:emp.ativo!==false,mustChangePwd:!!emp.mustChangePwd}));
  const [pwd,setPwd]=useState("");const [pwd2,setPwd2]=useState("");const [showPwd,setShowPwd]=useState(false);const [tempShown,setTempShown]=useState("");
  const set=(k,val)=>setV(o=>({...o,[k]:val}));
  const toggleView=(d)=>setV(o=>({...o,view:o.view.includes(d)?o.view.filter(x=>x!==d):[...o.view,d]}));
  const dup=employees.some(e=>e.user===v.user.trim().toLowerCase()&&e.id!==v.id);
  const cpfBad=v.cpf.trim()&&!validCPF(v.cpf);
  const pwdTyped=pwd.length>0||pwd2.length>0;
  const pwdNeeded=isNew||pwdTyped;
  const pwdMismatch=pwdNeeded&&pwd!==pwd2;
  const pwdMissing=isNew&&!pwd.trim();
  const ok=v.nome.trim()&&v.user.trim()&&!dup&&!pwdMismatch&&!pwdMissing;
  const useTemp=()=>{const t=genTempPwd();setPwd(t);setPwd2(t);setShowPwd(true);setTempShown(t);set("mustChangePwd",true);};
  const save=()=>{ if(!ok)return; const base={...v,user:v.user.trim().toLowerCase(),nome:v.nome.trim(),dept:v.isAdmin?"admin":v.dept,deptEdit:v.isAdmin?"":v.dept,view:v.isAdmin?VIEW_ALL.slice():v.view};
    if(pwdTyped||isNew){base.pwd=hashPwd(pwd);}else{base.pwd=emp.pwd;}  // edição em branco mantém a senha atual
    onSave(base); };
  const inputS={width:"100%",padding:"9px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:C.field,fontSize:14.5,color:C.ink,marginTop:5};
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.45)",display:"grid",placeItems:"center",zIndex:30}}>
    <div onClick={e=>e.stopPropagation()} style={{width:580,maxWidth:"95%",maxHeight:"92%",overflow:"auto",background:C.card,borderRadius:14,padding:"22px 24px",animation:"pop .2s ease"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{margin:0,fontSize:21.5,fontWeight:800,color:C.ink}}>{isNew?"Novo funcionário":"Editar funcionário"}</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button></div>
      <div style={{display:"flex",alignItems:"center",gap:14,marginTop:14}}>
        <Avatar nome={v.nome} src={v.avatar} size={64} fs={26} />
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          <label style={{...ghostBtn,cursor:"pointer"}}><Camera size={14}/> {v.avatar?"Trocar foto":"Enviar foto"}<input type="file" accept="image/*" style={{display:"none"}} onChange={e=>{const f=e.target.files&&e.target.files[0];fileToAvatar(f,(d)=>set("avatar",d));}} /></label>
          {v.avatar&&<button onClick={()=>set("avatar","")} style={{...ghostBtn,color:C.red,borderColor:C.redSoft,fontSize:12.5,padding:"5px 10px"}}>Remover foto</button>}
        </div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px",marginTop:14}}>
        <div style={{gridColumn:"1 / span 2"}}><label style={fl}>Nome completo *</label><input value={v.nome} onChange={e=>set("nome",e.target.value)} style={inputS} placeholder="Nome e sobrenome" /></div>
        <div><label style={fl}>CPF</label><input value={v.cpf} onChange={e=>set("cpf",e.target.value)} style={{...inputS,borderColor:cpfBad?C.amber:C.line}} placeholder="000.000.000-00" />{cpfBad&&<div style={{fontSize:12,color:C.amber,marginTop:3,display:"flex",alignItems:"center",gap:4}}><AlertTriangle size={11}/>CPF inválido</div>}</div>
        <div><label style={fl}>E-mail</label><input value={v.email} onChange={e=>set("email",e.target.value)} style={inputS} placeholder="nome@contabilizar.com" /></div>
        <div><label style={fl}>Cargo</label><input value={v.cargo} onChange={e=>set("cargo",e.target.value)} style={inputS} placeholder="Ex.: Analista Fiscal" /></div>
        <div><label style={fl}>Departamento</label><select value={v.dept} disabled={v.isAdmin} onChange={e=>set("dept",e.target.value)} style={{...inputS,cursor:v.isAdmin?"not-allowed":"pointer"}}>{["fiscal","pessoal","contabil","paralegal","financeiro","recepcao","rh","motoboy"].map(d=><option key={d} value={d}>{DEPT_LABEL[d]}</option>)}</select></div>
      </div>
      <div style={{height:1,background:C.line,margin:"16px 0 4px"}} />
      <div style={{fontSize:13,fontWeight:800,color:C.navy,letterSpacing:.4,textTransform:"uppercase",margin:"8px 0"}}><KeyRound size={13} style={{verticalAlign:-2,marginRight:5}} />Credenciais de acesso</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px"}}>
        <div><label style={fl}>Usuário *</label><input value={v.user} onChange={e=>set("user",e.target.value)} style={{...inputS,borderColor:dup?C.red:C.line}} placeholder="usuario.login" />{dup&&<div style={{fontSize:12.5,color:C.red,marginTop:3}}>Usuário já existe.</div>}</div>
        <div><label style={fl}>{isNew?"Senha *":"Nova senha"}</label><div style={{position:"relative"}}><input type={showPwd?"text":"password"} value={pwd} onChange={e=>setPwd(e.target.value)} style={{...inputS,paddingRight:38,borderColor:pwdMissing?C.red:C.line}} placeholder={isNew?"defina a senha":"deixe em branco p/ manter"} /><button type="button" onClick={()=>setShowPwd(s=>!s)} style={{position:"absolute",right:8,top:11,background:"none",border:"none",cursor:"pointer",color:C.muted}}>{showPwd?<EyeOff size={15}/>:<Eye size={15}/>}</button></div></div>
        <div><label style={fl}>{isNew?"Confirmar senha *":"Confirmar nova senha"}</label><input type={showPwd?"text":"password"} value={pwd2} onChange={e=>setPwd2(e.target.value)} style={{...inputS,borderColor:pwdMismatch?C.red:C.line}} placeholder="repita a senha" />{pwdMismatch&&<div style={{fontSize:12.5,color:C.red,marginTop:3}}>As senhas não coincidem.</div>}</div>
        <div style={{display:"flex",alignItems:"flex-end"}}><button onClick={useTemp} style={{...ghostBtn,fontSize:13}}><RefreshCw size={13}/> Gerar senha temporária</button></div>
      </div>
      {tempShown&&<div style={{marginTop:10,padding:"10px 13px",borderRadius:9,background:C.amberSoft,border:`1px solid ${C.amber}`,fontSize:13,color:C.amber,display:"flex",alignItems:"center",gap:8}}><KeyRound size={14}/>Senha temporária: <b className="tnum" style={{fontSize:15}}>{tempShown}</b> · anote e repasse. O usuário trocará no 1º acesso.</div>}
      <label style={{...chk,marginTop:8}}><input type="checkbox" checked={v.mustChangePwd} onChange={e=>set("mustChangePwd",e.target.checked)} /> Exigir <b>troca de senha no próximo acesso</b></label>
      <div style={{height:1,background:C.line,margin:"16px 0 4px"}} />
      <div style={{fontSize:13,fontWeight:800,color:C.navy,letterSpacing:.4,textTransform:"uppercase",margin:"8px 0"}}><ShieldCheck size={13} style={{verticalAlign:-2,marginRight:5}} />Permissões de acesso</div>
      <label style={chk}><input type="checkbox" checked={v.isAdmin} onChange={e=>set("isAdmin",e.target.checked)} /> <b>Administrador</b> · acesso total e gestão da equipe</label>
      <label style={chk}><input type="checkbox" checked={v.ativo} onChange={e=>set("ativo",e.target.checked)} /> Funcionário ativo (pode acessar o sistema)</label>
      {!v.isAdmin&&<><label style={chk}><input type="checkbox" checked={v.canCentral} onChange={e=>set("canCentral",e.target.checked)} /> Pode incluir/excluir empresas e mudar situação (Cadastro Central)</label>
      <label style={chk}><input type="checkbox" checked={v.canAssign} onChange={e=>set("canAssign",e.target.checked)} /> Pode <b>atribuir o responsável</b> das empresas do seu departamento</label>
      <label style={chk}><input type="checkbox" checked={v.onlyAssigned} onChange={e=>set("onlyAssigned",e.target.checked)} /> Edita <b>apenas</b> as empresas atribuídas a ele (demais só visualiza)</label>
      <div style={{fontSize:13,fontWeight:700,color:C.muted,margin:"12px 0 6px"}}>Departamentos que pode VISUALIZAR (edita só o seu: {DEPT_LABEL[v.dept]})</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px 10px"}}>{VIEW_ALL.map(d=><label key={d} style={{...chk,margin:0}}><input type="checkbox" checked={v.view.includes(d)} onChange={()=>toggleView(d)} /> {DEPT_LABEL[d]}</label>)}</div></>}
      <div style={{display:"flex",gap:10,marginTop:20,alignItems:"center"}}>
        {!isNew&&<button onClick={()=>onDelete(v.id,v.nome)} style={{padding:"10px 14px",borderRadius:9,border:`1px solid ${C.redSoft}`,background:C.redSoft,color:C.red,fontWeight:700,fontSize:14.5,cursor:"pointer"}}>Remover</button>}
        <div style={{flex:1}} /><button onClick={onClose} style={{padding:"10px 18px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:15,cursor:"pointer"}}>Cancelar</button>
        <button onClick={save} disabled={!ok} style={{padding:"10px 20px",borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:15,cursor:ok?"pointer":"not-allowed"}}>Salvar</button>
      </div>
    </div></div>;
}
const chk={display:"flex",alignItems:"center",gap:8,fontSize:14.5,color:C.body,margin:"7px 0",cursor:"pointer"};

const EMP_DEFAULTS={codigo:"",razao:"",nomeFantasia:"",cnpj:"",tipoPessoa:"PJ",regime:"SIMPLES NACIONAL",ie:"",im:"",cnae:"",segmento:"",dataAbertura:"",dataEntrada:"",cep:"",logradouro:"",numero:"",complemento:"",bairro:"",municipio:"",uf:"",telefone:"",whatsapp:"",email:"",contatoNome:"",responsavelLegal:"",cpfResponsavel:"",honorario:"",diaVencimento:"",certTipo:"–",certVenc:"",procEcac:"Não",tipoFolha:"FOLHA",situacao:"Ativo",dataSituacao:"",observacoes:""};
function EmpresaModal({emp,onClose,onSave,nextCode,regimes=[]}){
  const isNew=!emp;
  const [v,setV]=useState(()=>({...EMP_DEFAULTS,...(emp||{}),codigo:String(emp?emp.codigo:nextCode)}));
  const set=(k,val)=>setV(o=>({...o,[k]:val}));
  const cnpjD=onlyDigits(v.cnpj);
  const cnpjBad=v.cnpj.trim()&&!(cnpjD.length===11?validCPF(v.cnpj):cnpjD.length===14?validCNPJ(v.cnpj):false);
  const cpfRespBad=v.cpfResponsavel.trim()&&!validCPF(v.cpfResponsavel);
  const ok=v.razao.trim()&&v.cnpj.trim();
  const gi={width:"100%",padding:"9px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:C.field,fontSize:14.5,color:C.ink,marginTop:5,boxSizing:"border-box"};
  const F=(label,key,ph,o={})=>(<div style={o.span?{gridColumn:`1 / span ${o.span}`}:undefined}><label style={fl}>{label}</label><input type={o.type||"text"} value={v[key]||""} onChange={e=>set(key,e.target.value)} style={{...gi,...(o.bad?{borderColor:C.amber}:{})}} placeholder={ph||""} />{o.bad&&<div style={{fontSize:12,color:C.amber,marginTop:3,display:"flex",alignItems:"center",gap:4}}><AlertTriangle size={11}/>{o.badMsg||"Valor inválido"}</div>}</div>);
  const S=(label,key,opts,o={})=>(<div style={o.span?{gridColumn:`1 / span ${o.span}`}:undefined}><label style={fl}>{label}</label><select value={v[key]} onChange={e=>set(key,e.target.value)} style={{...gi,cursor:"pointer"}}>{opts.map(x=>Array.isArray(x)?<option key={x[0]} value={x[0]}>{x[1]}</option>:<option key={x} value={x}>{x}</option>)}</select></div>);
  const Sec=({children})=>(<div style={{fontSize:12.5,fontWeight:800,color:C.navy,letterSpacing:.5,textTransform:"uppercase",margin:"18px 0 2px",paddingBottom:6,borderBottom:`1px solid ${C.line}`}}>{children}</div>);
  const grid={display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px",marginTop:8};
  const UFS=["AC","AL","AP","AM","BA","CE","DF","ES","GO","MA","MT","MS","MG","PA","PB","PR","PE","PI","RJ","RN","RS","RO","RR","SC","SP","SE","TO"];
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.45)",display:"grid",placeItems:"center",zIndex:20}}>
    <div onClick={e=>e.stopPropagation()} style={{width:700,maxWidth:"96%",background:C.card,borderRadius:14,padding:"22px 26px",animation:"pop .2s ease",maxHeight:"94%",overflow:"auto"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{margin:0,fontSize:21.5,fontWeight:800,color:C.ink}}>{isNew?"Nova empresa":"Cadastro da empresa"}</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button></div>
      <p style={{fontSize:13.5,color:C.muted,marginTop:4}}>Cadastro central único. Os responsáveis (fiscal/pessoal) são definidos em cada departamento.</p>

      <Sec>Identificação</Sec>
      <div style={grid}>
        <div style={{display:"flex",gap:12}}><div style={{flex:"0 0 96px"}}>{F("Código","codigo","000")}</div><div style={{flex:1}}>{F("Razão social *","razao","EMPRESA LTDA")}</div></div>
        {F("Nome fantasia","nomeFantasia","Nome fantasia")}
        <div><label style={fl}>CNPJ / CPF *</label><input value={v.cnpj} onChange={e=>set("cnpj",e.target.value)} style={{...gi,borderColor:cnpjBad?C.amber:C.line}} placeholder="00.000.000/0001-00" />{cnpjBad&&<div style={{fontSize:12,color:C.amber,marginTop:3,display:"flex",alignItems:"center",gap:4}}><AlertTriangle size={11}/>CNPJ/CPF inválido</div>}</div>
        {S("Tipo de pessoa","tipoPessoa",["PJ","MEI","PF / Autônomo","Doméstica","Produtor rural"])}
        {F("Data de abertura","dataAbertura","",{type:"date"})}
        {F("Entrada no escritório","dataEntrada","",{type:"date"})}
        {S("Situação","situacao",["Ativo","Inativo","Bloqueada","Baixada","Suspensa","Distrato"])}
        {v.situacao!=="Ativo"&&F("Data da situação","dataSituacao","",{type:"date"})}
      </div>

      <Sec>Dados tributários</Sec>
      <div style={grid}>
        <div><label style={fl}>Regime</label><select value={v.regime} onChange={e=>set("regime",e.target.value)} style={{...gi,cursor:"pointer"}}>{(regimes.length?regimes:REGIME_SEED).map(r=><option key={r.nome}>{r.nome}</option>)}</select></div>
        {F("Atividade / segmento","segmento","Ex.: Comércio varejista")}
        {F("Inscrição Estadual (IE)","ie","ISENTO ou número")}
        {F("Inscrição Municipal (IM)","im","Número")}
        {F("CNAE principal","cnae","0000-0/00")}
        {S("Procuração e-CAC","procEcac",["Sim","Não"])}
      </div>

      <Sec>Endereço</Sec>
      <div style={grid}>
        {F("CEP","cep","00000-000")}
        {F("Logradouro","logradouro","Rua / Av.",{span:1})}
        {F("Número","numero","000")}
        {F("Complemento","complemento","Sala / Bloco")}
        {F("Bairro","bairro","Bairro")}
        {F("Município","municipio","Cidade")}
        {S("UF","uf",UFS)}
      </div>

      <Sec>Contato</Sec>
      <div style={grid}>
        {F("Telefone","telefone","(00) 0000-0000")}
        {F("WhatsApp","whatsapp","(00) 00000-0000")}
        {F("E-mail","email","contato@empresa.com",{type:"email",span:2})}
        {F("Pessoa de contato","contatoNome","Nome do contato",{span:2})}
      </div>

      <Sec>Responsável legal / sócio</Sec>
      <div style={grid}>
        {F("Nome do responsável legal","responsavelLegal","Sócio administrador")}
        {F("CPF do responsável","cpfResponsavel","000.000.000-00",{bad:cpfRespBad,badMsg:"CPF inválido"})}
      </div>

      <Sec>Honorários e operacional</Sec>
      <div style={grid}>
        {F("Honorário mensal (R$)","honorario","0,00")}
        {F("Dia de vencimento","diaVencimento","Ex.: 10")}
        {S("Tipo de folha","tipoFolha",["FOLHA","PRÓ-LABORE","SEM FOLHA"])}
        <div/>
        {S("Certificado digital","certTipo",["–","A1","A3"])}
        {v.certTipo!=="–"&&F("Validade do certificado","certVenc","",{type:"date"})}
      </div>

      <Sec>Observações</Sec>
      <textarea value={v.observacoes} onChange={e=>set("observacoes",e.target.value)} placeholder="Anotações gerais do cadastro…" style={{width:"100%",minHeight:64,marginTop:8,padding:"10px 12px",borderRadius:8,border:`1px solid ${C.line}`,background:C.field,fontSize:14,color:C.ink,resize:"vertical",fontFamily:"inherit",boxSizing:"border-box"}} />

      <div style={{display:"flex",gap:10,marginTop:22,position:"sticky",bottom:0}}><button onClick={onClose} style={{flex:1,padding:11,borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:15,cursor:"pointer"}}>Cancelar</button><button onClick={()=>ok&&onSave(v)} disabled={!ok} style={{flex:1,padding:11,borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:15,cursor:ok?"pointer":"not-allowed"}}>{isNew?"Incluir empresa":"Salvar cadastro"}</button></div>
    </div></div>;
}

function NotifBell({count,items}){
  const [open,setOpen]=useState(false);
  return <div style={{position:"relative"}} onBlur={()=>setTimeout(()=>setOpen(false),180)}>
    <button onClick={()=>setOpen(o=>!o)} title="Notificações" style={{position:"relative",width:40,height:40,borderRadius:9,border:`1px solid ${C.line}`,background:C.card,color:C.body,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
      <Bell size={18}/>
      {count>0&&<span style={{position:"absolute",top:-5,right:-5,minWidth:18,height:18,borderRadius:9,background:C.red,color:"#fff",fontSize:10.5,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 4px",border:`2px solid ${C.card}`}}>{count>9?"9+":count}</span>}
    </button>
    {open&&<div style={{position:"absolute",top:"calc(100% + 8px)",right:0,width:330,maxWidth:"90vw",background:C.card,border:`1px solid ${C.line}`,borderRadius:12,boxShadow:"0 12px 36px rgba(12,22,64,.2)",zIndex:60,overflow:"hidden"}}>
      <div style={{padding:"11px 15px",borderBottom:`1px solid ${C.line}`,fontSize:13.5,fontWeight:800,color:C.ink,display:"flex",alignItems:"center",gap:8}}><Bell size={14} color={C.navy}/> Notificações{count>0&&<span style={{marginLeft:"auto",fontSize:12,fontWeight:700,color:C.red}}>{count} pendente{count!==1?"s":""}</span>}</div>
      <div style={{maxHeight:360,overflowY:"auto"}}>
        {items.length===0&&<div style={{padding:"20px 15px",fontSize:13.5,color:C.muted,textAlign:"center"}}>Sem novidades por aqui. 🎉</div>}
        {items.map((it,i)=>{const Ic=it.icon||Dot;const clickable=!!it.onClick;return <button key={i} onMouseDown={()=>{if(it.onClick){it.onClick();setOpen(false);}}} disabled={!clickable} className={clickable?"rowh":""} style={{width:"100%",textAlign:"left",border:"none",borderBottom:`1px solid ${C.line}`,background:"transparent",padding:"10px 14px",cursor:clickable?"pointer":"default",display:"flex",gap:10,alignItems:"flex-start",opacity:it.muted?.85:1}}>
          <Ic size={16} color={it.color||C.muted} style={{marginTop:1,flexShrink:0}}/>
          <span style={{flex:1,minWidth:0}}><span style={{display:"block",fontSize:13.5,fontWeight:700,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{it.title}</span><span style={{display:"block",fontSize:12.5,color:C.muted,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{it.sub}</span></span>
          {clickable&&<ChevronRight size={14} color={C.muted} style={{flexShrink:0,marginTop:2}}/>}
        </button>;})}
      </div>
    </div>}
  </div>;
}

function Login({employees,onLogin,themeR,theme,setTheme}){
  const [u,setU]=useState("");const [p,setP]=useState("");const [err,setErr]=useState("");
  const [showPwd,setShowPwd]=useState(false);
  const [fails,setFails]=useState(0);
  const [lockUntil,setLockUntil]=useState(0);
  const [now,setNow]=useState(Date.now());
  // restaura bloqueio persistido (não some ao recarregar a página)
  useEffect(()=>{if(typeof window!=="undefined"&&window.storage){window.storage.get(LOCK_KEY,false).then(r=>{if(r&&r.value){const o=JSON.parse(r.value);if(o&&o.until>Date.now()){setLockUntil(o.until);setFails(o.fails||5);}}}).catch(()=>{});}},[]);
  useEffect(()=>{if(lockUntil<=now)return;const t=setInterval(()=>setNow(Date.now()),500);return ()=>clearInterval(t);},[lockUntil,now]);
  const locked=lockUntil>now;
  const secsLeft=Math.max(0,Math.ceil((lockUntil-now)/1000));
  const persistLock=(until,f)=>{if(typeof window!=="undefined"&&window.storage){if(until>Date.now())window.storage.set(LOCK_KEY,JSON.stringify({until,fails:f}),false).catch(()=>{});else window.storage.delete(LOCK_KEY,false).catch(()=>{});}};
  const go=()=>{
    if(locked)return;
    const id=u.trim().toLowerCase();
    const e=employees.find(x=>(x.user===id||(x.email&&x.email.trim().toLowerCase()===id))&&pwdMatches(x.pwd,p)&&x.ativo);
    if(e){setFails(0);persistLock(0,0);onLogin(e);return;}
    const nf=fails+1;setFails(nf);
    if(nf>=5){const until=Date.now()+5*60*1000;setLockUntil(until);persistLock(until,nf);setErr("Muitas tentativas. Acesso bloqueado por 5 minutos.");}
    else setErr(`Usuário/senha inválidos ou acesso inativo. (${5-nf} tentativa${5-nf!==1?"s":""} restante${5-nf!==1?"s":""})`);
  };
  const [mode,setMode]=useState("login");
  const [fq,setFq]=useState("");const [fres,setFres]=useState(null);
  const admins=employees.filter(e=>e.isAdmin&&e.ativo);
  const findForReset=()=>{const id=fq.trim().toLowerCase();if(!id){setFres(null);return;}const e=employees.find(x=>x.user===id||(x.email&&x.email.trim().toLowerCase()===id));setFres(e?{found:true,nome:e.nome}:{found:false});};
  return <div data-theme={themeR} className="login" style={{display:"flex",height:"100vh",overflow:"hidden",background:C.bg,color:C.ink}}><style>{FONTS}</style>
    <div className="login-left" style={{flex:1.05,background:C.navyDeep,color:"#fff",padding:"52px 52px",display:"flex",flexDirection:"column",justifyContent:"space-between",position:"relative",overflow:"hidden"}}>
      <div style={{position:"absolute",right:-100,top:-100,width:460,height:460,borderRadius:"50%",background:"radial-gradient(circle, rgba(99,133,224,.15), transparent 65%)",pointerEvents:"none"}} />
      <div style={{position:"absolute",left:-60,bottom:-60,width:300,height:300,borderRadius:"50%",background:"radial-gradient(circle, rgba(99,133,224,.1), transparent 65%)",pointerEvents:"none"}} />
      {/* logo com escrita · topo */}
      <div style={{position:"relative",display:"flex",flexDirection:"column",gap:6}}>
        <img src={LOGO_WORD} alt="CONTABILIZARe" style={{height:32,objectFit:"contain",objectPosition:"left",filter:"brightness(0) invert(1)",opacity:.96}} />
        <span style={{fontSize:10.5,letterSpacing:2.4,fontWeight:700,color:"rgba(255,255,255,.38)",textTransform:"uppercase"}}>Hub Interno</span>
      </div>
      {/* tagline · meio */}
      <div style={{position:"relative"}}>
        <h2 style={{fontSize:36,fontWeight:800,lineHeight:1.18,margin:0,maxWidth:400,letterSpacing:-0.5}}>Controle por competência,<br/>em um só lugar.</h2>
        <p style={{color:"rgba(185,192,212,.82)",fontSize:15,marginTop:18,maxWidth:360,lineHeight:1.65}}>Dashboard por departamento, progresso real e histórico de alterações.</p>
        <div style={{marginTop:30,display:"flex",flexDirection:"column",gap:13}}>
          {[["Todos os departamentos num só hub"],["Controle de acesso por perfil"],["Histórico completo de alterações"]].map(([tx])=><div key={tx} style={{display:"flex",alignItems:"center",gap:11,fontSize:13.5,color:"rgba(255,255,255,.68)"}}><div style={{width:5,height:5,borderRadius:"50%",background:"rgba(255,255,255,.4)",flexShrink:0}} />{tx}</div>)}
        </div>
      </div>
      {/* copyright · rodapé */}
      <div style={{position:"relative",fontSize:11.5,color:"rgba(255,255,255,.22)",letterSpacing:.3}}>&copy; {new Date().getFullYear()} Contabilizare &middot; Uso interno</div>
    </div>
    <div style={{flex:1,background:C.card,padding:"44px 50px",display:"flex",flexDirection:"column",justifyContent:"center",position:"relative"}}>
      {setTheme&&<div style={{position:"absolute",top:18,right:20,display:"flex",gap:6}}>{[["light",Sun],["dark",Moon],["system",Monitor]].map(([k,Ic])=>{const on=theme===k;return <button key={k} onClick={()=>setTheme(k)} title={k} style={{display:"flex",alignItems:"center",justifyContent:"center",width:32,height:32,borderRadius:8,border:`1px solid ${on?C.navy:C.line}`,background:on?C.navySoft:"transparent",color:on?C.navy:C.muted,cursor:"pointer"}}><Ic size={14}/></button>;})}</div>}
      <img src={LOGO_WORD} alt="CONTABILIZARe" className="logo" style={{height:28,alignSelf:"flex-start",marginBottom:24}} />
      {mode==="login"?<>
      <h1 style={{fontSize:27,fontWeight:800,margin:0,color:C.ink,letterSpacing:-0.3}}>Acessar o Hub</h1><p style={{color:C.muted,fontSize:15,marginTop:5}}>Entre com seu usuário ou e-mail do escritório.</p>
      <label style={lbl}>USUÁRIO OU E-MAIL</label><input value={u} disabled={locked} onChange={e=>{setU(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&go()} style={{...inp,opacity:locked?.6:1}} placeholder="seu.usuario" />
      <label style={lbl}>SENHA</label><div style={{position:"relative"}}><Lock size={15} color={C.muted} style={{position:"absolute",left:12,top:13}} /><input type={showPwd?"text":"password"} disabled={locked} value={p} onChange={e=>{setP(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&go()} style={{...inp,paddingLeft:34,paddingRight:40,opacity:locked?.6:1}} placeholder="••••••" /><button type="button" onClick={()=>setShowPwd(s=>!s)} title={showPwd?"Ocultar":"Mostrar"} style={{position:"absolute",right:8,top:9,background:"none",border:"none",cursor:"pointer",color:C.muted,padding:4}}>{showPwd?<EyeOff size={16}/>:<Eye size={16}/>}</button></div>
      {locked&&<div style={{marginTop:12,padding:"11px 13px",borderRadius:9,background:C.redSoft,border:`1px solid ${C.red}`,color:C.red,fontSize:13.5,fontWeight:600,display:"flex",alignItems:"center",gap:8}}><Lock size={15}/>Bloqueado · tente novamente em <b className="tnum">{Math.floor(secsLeft/60)}:{String(secsLeft%60).padStart(2,"0")}</b></div>}
      {err&&!locked&&<div style={{color:C.red,fontSize:14,marginTop:10}}>{err}</div>}
      <button onClick={go} disabled={locked} style={{marginTop:20,padding:12,borderRadius:9,border:"none",background:locked?C.line:C.navy,color:"#fff",fontSize:16,fontWeight:700,cursor:locked?"not-allowed":"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>Entrar <ArrowRight size={16} /></button>
      <button type="button" onClick={()=>{setMode("forgot");setErr("");}} style={{marginTop:14,alignSelf:"center",background:"none",border:"none",color:C.navy,fontSize:14,fontWeight:700,cursor:"pointer"}}>Esqueci minha senha</button>
      </>:<>
      <h1 style={{fontSize:27,fontWeight:800,margin:0,color:C.ink,letterSpacing:-0.3}}>Recuperar acesso</h1><p style={{color:C.muted,fontSize:15,marginTop:5,lineHeight:1.5}}>Informe seu usuário ou e-mail para ver como redefinir a senha.</p>
      <label style={lbl}>USUÁRIO OU E-MAIL</label><input value={fq} onChange={e=>{setFq(e.target.value);setFres(null);}} onKeyDown={e=>e.key==="Enter"&&findForReset()} style={inp} placeholder="seu.usuario" />
      <button onClick={findForReset} style={{marginTop:18,padding:12,borderRadius:9,border:"none",background:C.navy,color:"#fff",fontSize:15.5,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}><KeyRound size={16}/> Localizar acesso</button>
      {fres&&fres.found&&<div style={{marginTop:16,padding:"14px 16px",borderRadius:10,background:C.navySoft,border:`1px solid #dbe2f0`,fontSize:13.5,color:C.ink,lineHeight:1.6}}>
        <div style={{fontWeight:700,marginBottom:4,display:"flex",alignItems:"center",gap:7,color:C.navy}}><ShieldCheck size={15}/> Acesso encontrado: {fres.nome}</div>
        Por segurança, a redefinição é feita pelo administrador. Peça para ele(a) gerar uma <b>senha temporária</b> em <b>Equipe &amp; Acessos</b>. No seu próximo login você definirá uma nova senha.
        {admins.length>0&&<div style={{marginTop:10,paddingTop:10,borderTop:`1px solid #dbe2f0`}}><div style={{fontSize:12,fontWeight:700,color:C.muted,textTransform:"uppercase",letterSpacing:.4,marginBottom:5}}>Falar com</div>{admins.map(a=><div key={a.id} style={{fontSize:13.5,color:C.body}}>• {a.nome}{a.email?<span style={{color:C.muted}}> · {a.email}</span>:null}</div>)}</div>}
      </div>}
      {fres&&!fres.found&&<div style={{marginTop:16,padding:"13px 15px",borderRadius:10,background:C.amberSoft,border:`1px solid ${C.amber}`,fontSize:13.5,color:C.amber,display:"flex",gap:8,alignItems:"flex-start",lineHeight:1.5}}><AlertTriangle size={15} style={{marginTop:1,flexShrink:0}}/><span>Não encontramos esse usuário/e-mail. Confira os dados ou fale com o administrador do escritório.</span></div>}
      <button type="button" onClick={()=>{setMode("login");setFres(null);setFq("");}} style={{marginTop:16,alignSelf:"center",background:"none",border:"none",color:C.navy,fontSize:14,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",gap:6}}><ArrowLeft size={15}/> Voltar ao login</button>
      </>}
    </div></div>;
}

function ForcePwd({me,themeR,onDone,onLogout}){
  const [p1,setP1]=useState("");const [p2,setP2]=useState("");const [show,setShow]=useState(false);
  const short=p1.length>0&&p1.length<4; const mism=p2.length>0&&p1!==p2; const ok=p1.length>=4&&p1===p2;
  const inS={width:"100%",padding:"11px 12px",borderRadius:9,border:`1px solid ${C.line}`,background:C.field,fontSize:15,color:C.ink,marginTop:6};
  return <div data-theme={themeR} style={{display:"grid",placeItems:"center",height:"100vh",background:C.bg,color:C.ink,padding:16}}><style>{FONTS}</style>
    <div style={{width:420,maxWidth:"100%",background:C.card,border:`1px solid ${C.line}`,borderRadius:14,padding:"26px 28px",boxShadow:"0 12px 40px rgba(12,22,64,.18)"}}>
      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}><KeyRound size={20} color={C.navy}/><h2 style={{margin:0,fontSize:20,fontWeight:800,color:C.ink}}>Defina uma nova senha</h2></div>
      <p style={{color:C.muted,fontSize:14,marginTop:2,lineHeight:1.5}}>Olá, <b style={{color:C.ink}}>{me.nome}</b>. Por segurança, é necessário trocar a senha antes de continuar.</p>
      <label style={lbl}>NOVA SENHA</label><div style={{position:"relative"}}><input type={show?"text":"password"} value={p1} onChange={e=>setP1(e.target.value)} style={{...inS,borderColor:short?C.red:C.line,paddingRight:40}} placeholder="mínimo 4 caracteres" /><button type="button" onClick={()=>setShow(s=>!s)} style={{position:"absolute",right:9,top:13,background:"none",border:"none",cursor:"pointer",color:C.muted}}>{show?<EyeOff size={16}/>:<Eye size={16}/>}</button></div>{short&&<div style={{fontSize:12.5,color:C.red,marginTop:4}}>Use ao menos 4 caracteres.</div>}
      <label style={lbl}>CONFIRMAR SENHA</label><input type={show?"text":"password"} value={p2} onChange={e=>setP2(e.target.value)} onKeyDown={e=>e.key==="Enter"&&ok&&onDone(p1)} style={{...inS,borderColor:mism?C.red:C.line}} placeholder="repita a senha" />{mism&&<div style={{fontSize:12.5,color:C.red,marginTop:4}}>As senhas não coincidem.</div>}
      <button onClick={()=>ok&&onDone(p1)} disabled={!ok} style={{marginTop:18,width:"100%",padding:12,borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontSize:15.5,fontWeight:700,cursor:ok?"pointer":"not-allowed"}}>Salvar e entrar</button>
      <button onClick={onLogout} style={{marginTop:10,width:"100%",padding:10,borderRadius:9,border:`1px solid ${C.line}`,background:"transparent",color:C.muted,fontSize:14,fontWeight:600,cursor:"pointer"}}>Sair</button>
    </div></div>;
}

function MeuPerfil({me,onClose,onSave}){
  const [v,setV]=useState(()=>({nome:me.nome||"",email:me.email||"",cpf:me.cpf||"",avatar:me.avatar||""}));
  const [cur,setCur]=useState("");const [p1,setP1]=useState("");const [p2,setP2]=useState("");const [show,setShow]=useState(false);
  const set=(k,val)=>setV(o=>({...o,[k]:val}));
  const cpfBad=v.cpf.trim()&&!validCPF(v.cpf);
  const wantPwd=p1.length>0||p2.length>0||cur.length>0;
  const curBad=wantPwd&&!pwdMatches(me.pwd,cur);
  const shortPwd=p1.length>0&&p1.length<4; const mism=wantPwd&&p1!==p2;
  const pwdOk=!wantPwd||(!curBad&&p1.length>=4&&p1===p2);
  const ok=v.nome.trim()&&!cpfBad&&pwdOk;
  const save=()=>{if(!ok)return;const patch={nome:v.nome.trim(),email:v.email.trim(),cpf:v.cpf.trim(),avatar:v.avatar};if(wantPwd)patch.pwd=hashPwd(p1);onSave(patch);};
  return <Modal title="Meu perfil" onClose={onClose}>
    <div style={{display:"flex",alignItems:"center",gap:14,marginBottom:14}}>
      <Avatar nome={v.nome} src={v.avatar} size={60} fs={24} />
      <div style={{display:"flex",flexDirection:"column",gap:6}}>
        <label style={{...ghostBtn,cursor:"pointer"}}><Camera size={14}/> {v.avatar?"Trocar foto":"Enviar foto"}<input type="file" accept="image/*" style={{display:"none"}} onChange={e=>{const f=e.target.files&&e.target.files[0];fileToAvatar(f,(d)=>set("avatar",d));}} /></label>
        {v.avatar&&<button onClick={()=>set("avatar","")} style={{...ghostBtn,color:C.red,borderColor:C.redSoft,fontSize:12.5,padding:"5px 10px"}}>Remover foto</button>}
      </div>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px"}}>
      <div style={{gridColumn:"1 / span 2"}}><label style={fl}>Nome completo *</label><input value={v.nome} onChange={e=>set("nome",e.target.value)} style={fi} /></div>
      <div><label style={fl}>E-mail</label><input value={v.email} onChange={e=>set("email",e.target.value)} style={fi} placeholder="nome@contabilizar.com" /></div>
      <div><label style={fl}>CPF</label><input value={v.cpf} onChange={e=>set("cpf",e.target.value)} style={{...fi,borderColor:cpfBad?C.amber:C.line}} placeholder="000.000.000-00" />{cpfBad&&<div style={{fontSize:12,color:C.amber,marginTop:3}}>CPF inválido</div>}</div>
    </div>
    <div style={{height:1,background:C.line,margin:"16px 0 6px"}} />
    <div style={{fontSize:13,fontWeight:800,color:C.navy,letterSpacing:.4,textTransform:"uppercase",margin:"6px 0 4px"}}><KeyRound size={13} style={{verticalAlign:-2,marginRight:5}}/>Trocar senha <span style={{fontWeight:600,color:C.muted,textTransform:"none",letterSpacing:0}}>(opcional)</span></div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px"}}>
      <div style={{gridColumn:"1 / span 2"}}><label style={fl}>Senha atual</label><div style={{position:"relative"}}><input type={show?"text":"password"} value={cur} onChange={e=>setCur(e.target.value)} style={{...fi,borderColor:curBad?C.red:C.line,paddingRight:38}} placeholder="sua senha atual" /><button type="button" onClick={()=>setShow(s=>!s)} style={{position:"absolute",right:8,top:11,background:"none",border:"none",cursor:"pointer",color:C.muted}}>{show?<EyeOff size={15}/>:<Eye size={15}/>}</button></div>{curBad&&<div style={{fontSize:12.5,color:C.red,marginTop:3}}>Senha atual incorreta.</div>}</div>
      <div><label style={fl}>Nova senha</label><input type={show?"text":"password"} value={p1} onChange={e=>setP1(e.target.value)} style={{...fi,borderColor:shortPwd?C.red:C.line}} placeholder="mín. 4 caracteres" />{shortPwd&&<div style={{fontSize:12,color:C.red,marginTop:3}}>Mínimo 4 caracteres</div>}</div>
      <div><label style={fl}>Confirmar nova senha</label><input type={show?"text":"password"} value={p2} onChange={e=>setP2(e.target.value)} style={{...fi,borderColor:mism?C.red:C.line}} placeholder="repita a nova senha" />{mism&&<div style={{fontSize:12,color:C.red,marginTop:3}}>Não coincide</div>}</div>
    </div>
    <ModalFoot onClose={onClose} onSave={save} ok={!!ok} label="Salvar perfil" />
  </Modal>;
}

// ============================ MÓDULO RH ============================
const fi={width:"100%",padding:"9px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:C.field,fontSize:14.5,color:C.ink,marginTop:5};
function Modal({title,onClose,children,wide}){return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.45)",display:"grid",placeItems:"center",zIndex:30}}><div className="modal-box" onClick={e=>e.stopPropagation()} style={{width:wide?640:520,maxWidth:"95%",maxHeight:"92%",overflow:"auto",background:C.card,borderRadius:14,padding:"22px 24px",animation:"pop .2s ease"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}><h2 style={{margin:0,fontSize:21.5,fontWeight:800,color:C.ink}}>{title}</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20}/></button></div>{children}</div></div>;}
function ModalFoot({onClose,onSave,ok=true,label="Salvar"}){return <div style={{display:"flex",gap:10,marginTop:20,justifyContent:"flex-end"}}><button onClick={onClose} style={{padding:"10px 18px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:15,cursor:"pointer"}}>Cancelar</button><button onClick={onSave} disabled={!ok} style={{padding:"10px 20px",borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:15,cursor:ok?"pointer":"not-allowed"}}>{label}</button></div>;}
const Wrap=({children})=> <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}>{children}</div></div>;
const RH_MES=COMPS.slice().reverse();

function MiniEvol({data,color,height=56,label}){
  if(!data||!data.length)return null;
  const mx=Math.max(...data.map(d=>d.v),0.01);
  return <div style={{marginTop:10,paddingTop:8,borderTop:`1px solid ${C.line}`}}>
    {label&&<div style={{fontSize:11.5,color:C.muted,fontWeight:600,marginBottom:6}}>{label}</div>}
    <div style={{display:"flex",alignItems:"flex-end",gap:4,height}}>
      {data.map((d,i)=><div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:2}}>
        <div style={{width:"70%",background:color,borderRadius:"3px 3px 0 0",height:Math.max(2,Math.round(d.v/mx*(height-16)))}}/>
        <div style={{fontSize:9.5,color:C.muted,textAlign:"center",lineHeight:1.1}}>{d.l}</div>
      </div>)}
    </div>
  </div>;
}

function RhEmpty({cols,msg,sub,icon:Ic}){
  return <tr><td colSpan={cols} style={{textAlign:"center",padding:"36px 20px",color:C.muted}}>
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8}}>
      {Ic?<Ic size={30} color={C.line}/>:<Layers size={30} color={C.line}/>}
      <div style={{fontSize:14,fontWeight:700,color:C.body}}>{msg||"Nenhum registro encontrado"}</div>
      {sub&&<div style={{fontSize:12.5}}>{sub}</div>}
    </div>
  </td></tr>;
}

// ===== Utilitários RH: tempo (h:min), aniversariantes, adiantamentos =====
function fmtH(dec){const t=Math.round((+dec||0)*60);const h=Math.floor(t/60),m=t%60;if(!t)return "0h";return (h?h+"h":"")+(m?(h?" ":"")+m+"min":"");}
function birthMD(nasc){if(!nasc)return null;const p=String(nasc).split("-");if(p.length<3)return null;const m=+p[1],d=+p[2],y=+p[0];if(!m||!d)return null;return {m,d,y};}
function idadeQueFaz(nasc,ref){const b=birthMD(nasc);if(!b)return null;const r=ref||new Date();let a=r.getFullYear()-b.y;return a;}
function aniversariantesMes(colabs,mesIdx){return (colabs||[]).filter(c=>c.status==="Ativo"&&birthMD(c.nascimento)&&birthMD(c.nascimento).m===mesIdx).map(c=>({c,d:birthMD(c.nascimento).d})).sort((a,b)=>a.d-b.d);}
function aniversariantesProximos(colabs,dias){const hoje=new Date();hoje.setHours(0,0,0,0);const out=[];(colabs||[]).forEach(c=>{const b=birthMD(c.nascimento);if(!b||c.status!=="Ativo")return;let prox=new Date(hoje.getFullYear(),b.m-1,b.d);if(prox<hoje)prox=new Date(hoje.getFullYear()+1,b.m-1,b.d);const diff=Math.round((prox-hoje)/86400000);if(diff<=dias)out.push({c,diff,dia:b.d,mes:b.m});});return out.sort((a,b)=>a.diff-b.diff);}

function AniversariantesCard({colabs}){
  const prox=aniversariantesProximos(colabs,7);
  return <div style={{flex:1,minWidth:260,background:C.card,border:`1px solid ${C.line}`,borderRadius:13,padding:"16px 18px"}}>
    <div style={{fontSize:14,fontWeight:800,color:C.ink,marginBottom:12,display:"flex",alignItems:"center",gap:8}}>🎂 Aniversariantes da semana</div>
    {prox.length===0&&<div style={{fontSize:13.5,color:C.muted}}>Ninguém faz aniversário nos próximos 7 dias.</div>}
    {prox.map(({c,diff,dia,mes})=><div key={c.id} style={{display:"flex",alignItems:"center",gap:11,padding:"7px 0",borderBottom:`1px solid ${C.line}`}}>
      <Avatar nome={c.nome} src={c.foto} size={36} fs={15}/>
      <div style={{flex:1,minWidth:0}}><div style={{fontSize:14,fontWeight:700,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{c.nome}</div><div style={{fontSize:12.5,color:C.muted}}>{c.cargo}</div></div>
      <div style={{textAlign:"right"}}><div className="tnum" style={{fontSize:13.5,fontWeight:800,color:C.navy}}>{String(dia).padStart(2,"0")}/{String(mes).padStart(2,"0")}</div><div style={{fontSize:11.5,fontWeight:700,color:diff===0?C.green:C.muted}}>{diff===0?"Hoje! 🎉":diff===1?"Amanhã":`em ${diff} dias`}</div></div>
    </div>)}
  </div>;
}

function rhAlerts(rh){
  if(!rh)return [];
  const out=[];const today=new Date();today.setHours(0,0,0,0);const ym=CUR_YM;
  const ativos=(rh.colaboradores||[]).filter(c=>c.status==="Ativo");
  // Folha do mês pendente
  const semFolha=ativos.filter(c=>{const f=(rh.folha||{})[c.id+"|"+ym];return !f||!(+f.bruto>0);});
  if(semFolha.length)out.push({key:"folha",prio:2,icon:Wallet,color:C.amber,title:`Folha de ${compLabel(ym)} pendente`,sub:`${semFolha.length} colaborador(es) sem lançamento`});
  // Adiantamentos do mês (prazo de lançamento)
  const adMes=(rh.adiantamentos||[]).filter(a=>a.mesRef===ym);
  if(today.getDate()>=15&&adMes.length===0)out.push({key:"adiant",prio:1,icon:Wallet,color:"#5b6bd6",title:"Adiantamentos não lançados",sub:`Competência ${compLabel(ym)} sem registros`});
  // Demandas com prazo
  (rh.demandas||[]).forEach(d=>{const sla=demPrazoSLA(d);if(sla===null)return;const t=d.descricao||("Demanda #"+(d.num||d.id));if(sla<0)out.push({key:"dem-"+d.id,prio:3,icon:AlertCircle,color:C.red,title:"Demanda atrasada",sub:`${t} · ${-sla}d em atraso`});else if(sla<=3)out.push({key:"dem-"+d.id,prio:2,icon:Clock,color:C.amber,title:"Demanda próxima do prazo",sub:`${t} · vence em ${sla}d`});});
  // Aniversários da semana
  aniversariantesProximos(rh.colaboradores,7).forEach(({c,diff,dia,mes})=>out.push({key:"agg-"+c.id,prio:1,icon:Heart,color:"#d6457f",title:`🎂 ${c.nome}`,sub:diff===0?"Faz aniversário hoje!":diff===1?"Aniversário amanhã":`Aniversário em ${diff} dias (${String(dia).padStart(2,"0")}/${String(mes).padStart(2,"0")})`}));
  // Contrato de experiência (CLT recém-admitido · marcos 45 e 90 dias)
  ativos.forEach(c=>{if(!/clt/i.test(c.regime||"")||!c.adm)return;const adm=new Date(c.adm+"T00:00:00");if(isNaN(adm))return;const dias=Math.round((today-adm)/86400000);[45,90].forEach(marco=>{const faltam=marco-dias;if(faltam>=0&&faltam<=10)out.push({key:`exp-${c.id}-${marco}`,prio:2,icon:ClipboardList,color:C.amber,title:`Experiência (${marco}d) · ${c.nome}`,sub:faltam===0?"Marco é hoje":`Faltam ${faltam} dia(s) · admissão ${c.adm}`});});});
  // Aniversário de admissão (período aquisitivo de férias)
  ativos.forEach(c=>{if(!c.adm)return;const adm=new Date(c.adm+"T00:00:00");if(isNaN(adm)||adm>today)return;let prox=new Date(today.getFullYear(),adm.getMonth(),adm.getDate());if(prox<today)prox=new Date(today.getFullYear()+1,adm.getMonth(),adm.getDate());const faltam=Math.round((prox-today)/86400000);const anos=prox.getFullYear()-adm.getFullYear();if(faltam<=15&&anos>=1)out.push({key:`fer-${c.id}`,prio:1,icon:Calendar,color:C.navy,title:`Período de férias · ${c.nome}`,sub:`Completa ${anos} ano(s) de casa em ${faltam===0?"hoje":faltam+" dia(s)"}`});});
  return out.sort((a,b)=>b.prio-a.prio);
}

